-- WebChef — seed the recipe library.
--
-- Generated by scripts/fetch-recipes.mjs from the Spoonacular API. Do not edit
-- by hand: re-run the script to regenerate. Migrations run as a privileged role
-- and bypass RLS, which is exactly how course content is meant to be seeded.
--
-- Clears the previously imported recipes first so the library always matches the
-- current fetch exactly (an earlier import may have included recipes this one
-- doesn't). Recipes written by hand have no spoonacular_id and are left alone.
-- Nothing references recipes, so removing rows is safe.

delete from recipes where spoonacular_id is not null;

insert into recipes (
  spoonacular_id, title, description, image_url, source_url,
  ready_in_minutes, servings, cuisines, meals, ingredients, instructions
) values
  (633072, 'Authentic Chicken Enchiladas', 'Forget going out to eat or ordering takeout every time you crave Mexican food.  Try making Authentic Chicken Enchiladas at home.', 'https://img.spoonacular.com/recipes/633072-312x231.jpg', 'https://www.foodista.com/recipe/BXBVZXM8/authentic-chicken-enchiladas', 45, 12, array['Mexican']::text[], array['lunch', 'dinner']::text[], '[{"name":"chicken breasts","amount":4,"unit":"","original":"4 chicken breasts"},{"name":"chili powder","amount":0.5,"unit":"tsps","original":"1/2 teaspoon Chili Powder"},{"name":"corn tortillas","amount":45,"unit":"small","original":"45 small Corn Tortillas"},{"name":"cumin","amount":0.25,"unit":"tsps","original":"1/4 teaspoon Cumin"},{"name":"enchilada sauce","amount":1,"unit":"can","original":"1 can Enchilada sauce"},{"name":"garlic powder","amount":1,"unit":"tsp","original":"1 teaspoon Garlic Powder"},{"name":"chilis","amount":1,"unit":"can","original":"1 can diced green chilis"},{"name":"pickled jalapeno in a jar)","amount":0.5,"unit":"","original":"1/2 pickled jalapeno (we used about 5 slices of jalapenos (pickled) in a jar)"},{"name":"olive oil","amount":3,"unit":"Tbsps","original":"3 tablespoons olive oil"},{"name":"onion","amount":1,"unit":"","original":"1 onion, diced"},{"name":"salt and pepper","amount":12,"unit":"servings","original":"salt and pepper"},{"name":"mexican cheese blend","amount":1,"unit":"cup","original":"1 cup Mexican Cheese blend (plus more for topping)"}]'::jsonb, '["Season your thawed chicken breasts with salt and pepper.","Add a little bit of olive oil to your frying pan, add chicken, and cook through.","Remove chicken from pan, then add diced onions to the pan. Turn heat to medium and let onions saute through. (You may need to add a little bit more oil to the pan.)Meanwhile, chop up your chicken (or shred) very finely. When the onions are soft and translucent, add chicken back to the pan. Season your onions and chicken with garlic, cumin, and chili powder. Finely chop up your jalapeno and add that and your green chilis to your chicken mixture. Stir in your cheese. Now you are ready to assemble.","Heat up your olive oil in a small frying pan.","Add your corn tortilla for about 20 seconds, flipping if the oil doesn''t reach the top side. Doing this softens your tortilla so it won''t break as you roll it. Do this with all your tortillas and drain on paper towels.Take 2 cookie sheets and spray with cooking spray.","Lay out a tortilla and add about 2 TBSP of chicken mixture to the middle of your tortilla.","Roll up. Fill the remaining tortillas in the same way and line them up next to each other on your cookie sheet, so they are very close to each other, but not touching. This should make two rows on each of your cookie sheets.If two pans are too much for your family, then at this point, take one pan and put it in your freezer. Once the enchiladas are frozen, remove them from the pan and stack them in a double lined ziploc freezer bag. When you want to make them, simply line them up again on a greased cookie sheet, let thaw for about an hour on the counter, then bake as instructed.)Now, bake your enchiladas in the oven, at 400 degrees, for about 20 minutes. They should be lightly browned.","Remove them from the oven and spoon over about 2TBSP of your enchilada sauce over the top of each enchilada. Then sprinkle the tops with cheese.","Put the enchiladas back in the oven for about 7 minutes. After that, it''s time to eat!"]'::jsonb),
  (635063, 'Black Bean Brownies', 'The recipe Black Bean Brownies could satisfy your American craving in roughly 45 minutes.  One serving contains 233 calories, 5g of protein, and 12g of fat.', 'https://img.spoonacular.com/recipes/635063-312x231.jpg', 'https://www.foodista.com/recipe/BY3TN7TR/black-bean-brownies', 45, 12, array['American']::text[], array['dessert']::text[], '[{"name":"black beans","amount":15,"unit":"oz","original":"15 oz can black beans, rinsed and rained"},{"name":"canola oil","amount":2,"unit":"Tbsps","original":"2 tablespoons canola oil"},{"name":"applesauce","amount":0.25,"unit":"cups","original":"1/4 cup unsweetened applesauce"},{"name":"eggs","amount":2,"unit":"","original":"2 eggs"},{"name":"egg yolk","amount":1,"unit":"","original":"1 egg yolk"},{"name":"sugar","amount":0.75,"unit":"cups","original":"3/4 cup sugar"},{"name":"cocoa","amount":3,"unit":"Tbsps","original":"3 tablespoons unsweetened cocoa"},{"name":"espresso powder","amount":1.5,"unit":"Tbsps","original":"1 1/2 tablespoons instant espresso powder"},{"name":"semi-sweet chocolate","amount":3,"unit":"oz","original":"3 ounces semi-sweet chocolate, chopped"},{"name":"butter","amount":2,"unit":"Tbsps","original":"2 tablespoons unsalted butter"},{"name":"vanilla extract","amount":1,"unit":"tsp","original":"1 teaspoon vanilla extract"},{"name":"salt","amount":0.5,"unit":"tsps","original":"1/2 teaspoon salt"},{"name":"flour","amount":0.5,"unit":"cups","original":"1/2 cup all-purpose flour"},{"name":"walnuts","amount":0.5,"unit":"cups","original":"1/2 cup walnuts, chopped"}]'::jsonb, '["Preheat oven to 350 F.","Mix beans, oil, applesauce, eggs, egg yolk, sugar, cocoa powder, and espresso powder in your food processor. Pulse for 1 minute, or until smooth.","Place your chopped chocolate and butter in a small bowl and microwave for 1 minute, stirring halfway. Stir until the mixture is smooth. Set aside to cool for a few minutes.","Add chocolate/butter mixture, vanilla extract, and salt to the food processor; pulse to blend.","Pour batter into a large bowl and stir in the flour.","Spread batter into a foil-lined 8x8\" baking pan coated with nonstick cooking spray. Smooth the top and sprinkle evenly with the walnuts (if using).","Bake for 25 to 30 minutes, or until a toothpick inserted into the center comes out clean.","Let the brownies cool in the pan on a wire rack for 15 minutes.","Cut into squares and serve"]'::jsonb),
  (715769, 'Broccolini Quinoa Pilaf', 'Broccolini Quinoa Pilaf requires approximately 30 minutes from start to finish.  For $4.', 'https://img.spoonacular.com/recipes/715769-312x231.jpg', 'https://pickfreshfoods.com/broccolini-quinoa-pilaf/', 30, 2, array['Mediterranean', 'Italian', 'European']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"broccolini","amount":1,"unit":"bunch","original":"1 bunch broccolini, trimmed"},{"name":"garlic clove","amount":1,"unit":"","original":"1 garlic clove, minced"},{"name":"olive oil","amount":1,"unit":"Tbsp","original":"1 tbsp olive oil"},{"name":"onion","amount":0.5,"unit":"cups","original":"½ cup onion"},{"name":"quinoa","amount":1,"unit":"cup","original":"1 cup quinoa, rinsed"},{"name":"vegetable broth","amount":2,"unit":"cups","original":"2 cups vegetable broth"},{"name":"walnuts","amount":2,"unit":"oz","original":"2 oz chopped walnuts"}]'::jsonb, '["In a large pan with lid heat olive oil over medium high heat.","Add onions and cook for 1 minute.","Add garlic and cook until onions are translucent and garlic is fragrant.","Add quinoa to pan, stir to combine. Slowly add in broth and bring to a boil.Cover and reduce heat to low, cook for 15 minutes.In the last 2-3 minutes of cooking add in broccolini on top of the quinoa (do not stir) and cover.Uncover and toss broccolini and quinoa together.Season to taste with salt and pepper.","Add walnuts and serve hot."]'::jsonb),
  (716426, 'Cauliflower, Brown Rice, and Vegetable Fried Rice', 'The recipe Cauliflower, Brown Rice, and Vegetable Fried Rice is ready in around 30 minutes and is definitely a great gluten free, dairy free, lacto ovo vegetarian, and vegan option for lovers of Chinese food.  This recipe makes 8 servings with 248 calories, 7g of protein, and 13g of fat each.', 'https://img.spoonacular.com/recipes/716426-312x231.jpg', 'https://fullbellysisters.blogspot.com/2012/01/cauliflower-fried-rice-more-veggies.html', 30, 8, array['Chinese', 'Asian']::text[], array['snack']::text[], '[{"name":"grapeseed oil","amount":2,"unit":"Tbsps","original":"2 tablespoons grapeseed oil"},{"name":"coconut oil","amount":2,"unit":"Tbsps","original":"2 tablespoons coconut oil"},{"name":"scallions","amount":7,"unit":"","original":"7 scallions, chopped (keep white/light green ends separate from dark green tops)"},{"name":"garlic","amount":5,"unit":"cloves","original":"5 cloves of garlic, chopped"},{"name":"cauliflower","amount":1,"unit":"head","original":"head of cauliflower, raw"},{"name":"brown rice","amount":3,"unit":"cups","original":"3 cups of cooked brown rice, cold"},{"name":"broccoli","amount":2,"unit":"cups","original":"2 cups cooked broccoli, chopped small"},{"name":"peas","amount":1,"unit":"cup","original":"1 cup frozen peas"},{"name":"soy sauce","amount":3,"unit":"Tbsps","original":"3 T reduced-sodium soy sauce"},{"name":"sesame oil","amount":2,"unit":"tsps","original":"2 teaspoons toasted sesame oil"},{"name":"sesame seeds","amount":8,"unit":"servings","original":"toasted sesame seeds, optional"},{"name":"additional scallion tops","amount":8,"unit":"servings","original":"additional chopped scallion tops for garnish"},{"name":"salt","amount":8,"unit":"servings","original":"salt, to taste"}]'::jsonb, '["Remove the cauliflower''s tough stem and reserve for another use. Using a food processor, pulse cauliflower florets until they resemble rice or couscous. You should end up with around four cups of \"cauliflower rice.\"","Heat 1T butter and 1T oil in a large skillet over medium heat.","Add garlic and the white and light green pieces of scallion. Sauté about a minute.","Add the cauliflower to the pan. Stir to coat with oil, then spread out in pan and let sit; you want it cook a bit and to caramelize (get a bit brown), which will bring out the sweetness. After a couple of minutes, stir and spread out again.","Add cold rice (it separates easily, so it won''t clump up during cooking), plus the additional grapeseed and coconut oil or butter. Raise heat to medium-high. Toss everything together and, again, spread the mixture out over the whole pan and press a bit into the bottom.","Let it sit for about two minutes—so the rice can get toasted and a little crispy.","Add the peas and broccoli and stir again.","Drizzle soy sauce and toasted sesame oil over rice.Cook for another minute or so and turn off heat.","Add chopped scallion tops and toss.I like to toast some sesame seeds in a dry pan; I sprinkle these and some more raw, chopped scallion over the top of the rice for added flavor and crunch.Season to taste with salt and, if you''d like, more soy sauce. Keep in mind that if you''re serving this with something salty and saucy (ie. teriyaki chicken) you may want to hold off on adding too much salt to the fried rice."]'::jsonb),
  (715421, 'Cheesy Chicken Enchilada Quinoa Casserole', 'Cheesy Chicken Enchilada Quinoa Casserole might be just the Mexican recipe you are searching for.  One serving contains 594 calories, 34g of protein, and 24g of fat.', 'https://img.spoonacular.com/recipes/715421-312x231.jpg', 'https://www.pinkwhen.com/cheesy-chicken-enchilada-quinoa-casserole/', 30, 4, array['Mexican']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"avocado","amount":1,"unit":"small","original":"1 small Avocado (chopped)"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"½ tsp black pepper"},{"name":"black beans","amount":15,"unit":"oz","original":"1 (15oz) can of black beans (I like the low sodium version)"},{"name":"canned tomatoes","amount":10,"unit":"oz","original":"1 (10oz) can of tomatoes with green chilis"},{"name":"chili powder","amount":0.5,"unit":"tsps","original":"½ tsp chili powder"},{"name":"quinoa","amount":1,"unit":"cup","original":"1 cup cooked quinoa"},{"name":"cumin","amount":0.5,"unit":"tsps","original":"½ tsp cumin"},{"name":"verde enchilada sauce","amount":10,"unit":"oz","original":"1 (10oz) can of verde enchilada sauce"},{"name":"cilantro","amount":2,"unit":"Tbsps","original":"fresh cilantro (2Tbsp and 2 tsp separated)"},{"name":"green onion tops","amount":4,"unit":"servings","original":"green onion tops (chopped)"},{"name":"roma tomato","amount":1,"unit":"","original":"1 Roma tomato (chopped)"},{"name":"salt","amount":4,"unit":"servings","original":"salt to taste"},{"name":"cheese","amount":2,"unit":"cups","original":"2 cups of shredded cheese (my favorite is the Kraft Mexican 4 cheese blend and one bag equals two cups!)"},{"name":"chicken breast","amount":1,"unit":"","original":"1 boneless skinless chicken breast (boiled and shredded)"},{"name":"corn","amount":15,"unit":"oz","original":"1 (15oz) can of sweet corn (you are only going to use half of the can)"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"½ tsp white pepper"}]'::jsonb, '["To get started, heat your oven to 350 and prepare an 8x8 baking dish. Cook the quinoa according to the instructions. If you haven''t already, boil and shred your chicken breast.In a medium sized mixing bowl add 2 Tbsp cilantro, 1 cup shredded cheese, quinoa, tomatoes with chilis, black beans, half of the can of sweet corn, verde enchilada sauce, cumin, chili powder, white pepper, black pepper, and salt to taste.","Mix everything well, and then pour into the 8 x8 baking dish. Cover with the last cup of cheese and then bake in the oven for 15 minutes.","Remove from oven and allow to cool for 5 minutes. Then top with chopped Roma tomato, chopped avocado, green onion tops, and remaining 2 tsp of cilantro.","Serve immediately."]'::jsonb),
  (715394, 'Chicken Enchilada Casserole', 'Chicken Enchilada Casserole might be just the main course you are searching for.  This recipe makes 8 servings with 325 calories, 26g of protein, and 12g of fat each.', 'https://img.spoonacular.com/recipes/715394-312x231.jpg', 'https://www.pinkwhen.com/chicken-enchilada-casserole-recipe/', 45, 8, array['Mexican']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"verde enchilada sauce","amount":20,"unit":"oz","original":"2 10oz cans verde enchilada sauce"},{"name":"cheese","amount":2,"unit":"cups","original":"2 cups shredded cheese"},{"name":"chicken pre","amount":1,"unit":"lb","original":"1 lb shredded chicken pre cooked"},{"name":"canned tomatoes","amount":10,"unit":"oz","original":"1 10oz can tomatoes with green chilis"},{"name":"refried beans","amount":15,"unit":"oz","original":"1 15oz can refried beans"},{"name":"flour tortillas torn into bite sized pieces","amount":6,"unit":"","original":"6-8 flour tortillas torn into bite sized pieces"},{"name":"green onion tops optional","amount":8,"unit":"servings","original":"green onion tops optional"}]'::jsonb, '["Heat oven to 37","Prepare a 9 x 13 baking dish and begin by placing a layer of tortillas on the bottom of the dish.","Then add a layer of chicken and 1/4 a cup of the shredded cheese.","Add on half a can of tomatoes and green chilies and one can of the verde enchilada sauce.","Finish the layer with a half a can of the refried beans.","Then cover with another layer of flour tortilla pieces, and start the layering process again.","Once you are finished layering, cover the top with the remaining shredded cheese.","Cover with foil, and then bake in the oven for 30 minutes.","Remove the foil, add a few green onion tops, and bake for an additional 5 minutes until the cheese is melted and bubbly. Allow to sit for 10-15 minutes to allow to cool before serving. Serving any sooner may give you a soupy, but still delicious dinner."]'::jsonb),
  (638693, 'Chinese Potstickers', 'If you have approximately 45 minutes to spend in the kitchen, Chinese Potstickers might be an excellent dairy free recipe to try.  This recipe makes 24 servings with 135 calories, 4g of protein, and 5g of fat each.', 'https://img.spoonacular.com/recipes/638693-312x231.jpg', 'https://www.foodista.com/recipe/GNBC6TDX/chinese-potstickers', 45, 24, array['Chinese', 'Asian']::text[], array['snack']::text[], '[{"name":"ground pork","amount":7.055,"unit":"oz","original":"200g ground pork (slightly fatty, not lean)"},{"name":"water chestnuts","amount":3.527,"unit":"oz","original":"100g canned water chestnuts (or chopped spinach/cabbage)"},{"name":"sea salt","amount":1,"unit":"tsp","original":"1 teaspoon sea salt"},{"name":"sugar","amount":1,"unit":"tsp","original":"1 teaspoon fine sugar"},{"name":"ground pepper","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground black pepper"},{"name":"soy sauce","amount":2,"unit":"tsps","original":"2 teaspoons light soy sauce"},{"name":"sesame oil","amount":2,"unit":"tsps","original":"2 teaspoons sesame oil"},{"name":"shaoxing huatiao wine","amount":1,"unit":"Tbsp","original":"1 tablespoon Shaoxing Huatiao wine"},{"name":"scallions","amount":2,"unit":"Tbsps","original":"2 to 3 tablespoons of chopped scallions (spring onions)"},{"name":"dumpling wrappers","amount":25,"unit":"","original":"25 to 30 store bought dumpling wrappers (the round kind, not the square wanton or spring roll wrappers)"},{"name":"flour to dust","amount":24,"unit":"servings","original":"Plain flour to dust"},{"name":"vegetable oil","amount":4,"unit":"Tbsps","original":"4 to 6 tablespoons vegetable oil (for 2 batches of cooking)"},{"name":"water","amount":0.6666667,"unit":"cups","original":"2/3 cups water (for 2 batches of cooking)"}]'::jsonb, '["Place 200g of ground pork in a large mixing bowl. If preferred, pork may be substituted with ground chicken.","Add 1 teaspoon of sea salt, 1 teaspoon of fine sugar, add 1/2 teaspoon of ground black pepper, 2 teaspoons of light soy sauce, 2 teaspoons of sesame oil and 1 tablespoon of Shaoxing Huatiao wine.","Place 100g of canned water chestnuts in a chopper/blender. Chop the water chestnuts to small pieces.","Add the chopped water chestnuts to the pork mixture. If preferred, use spinach or cabbage in place of water chestnuts.","Add 2 to 3 tablespoons of finely chopped scallions or spring onions to the pork mixture.","Combine all the filling ingredients well.","Thaw the dumpling wrappers if they are frozen. Keep them well covered until they are ready to be used.","Dust a dish generously with flour. This will hold the dumplings once they are made.","Dust the table generously with flour. Carefully separate the sheets of dumpling wrappers and lay them on the table. Fill each wrapper with about 1.5 teaspoons of the prepared pork filling.","Prepare a bowl of water. Dip finger into the water and lightly wet the rim of each dumpling wrapper.","Bring the dumpling wrapper together till the opposite ends meet. Gently push the filling into the wrapper and pinch the top tip of the dumpling wrapper to seal it.","From the centre of the dumpling, fold a pleat on ONE side and bring it to the other side of the dumpling. Fold towards the centre of the dumpling. Pinch to seal it.","Repeat and create a 2nd pleat. Be mindful to pinch tight to seal the dumpling well. Repeat and create a 3rd pleat. Each side should have 3 pleats.","Repeat the same pleating on the other end of the dumpling. Always ensure that the pleats face the centre of the dumpling.","Place all prepared dumplings in a well floured dish ensuring that they do not touch each other. Set aside till ready to cook. They can also be frozen at this stage.","To cook the potstickers, add 2 to 3 tablespoons of vegetable oil to a very hot frying pan. The potstickers should be cooked in at least 2 batches.","When the oil is hot, add the dumplings ensuring that the flat surfaces face down. Pan fry till the bottoms of the dumplings are a nice golden brown.","Add 1/3 cup of water to the pan. Cover the pan immediately and let the steam cook the dumplings for 4 to 5 minutes.","Once the water has evaporated, remove the cover and let the dumplings sit in the hot pan for another minute for its base to crisp up again. These are now Chinese potstickers.","Gently transfer the potstickers to a plate.","Serve immediately.","These Chinese potstickers are best served with a vinegar dip made with balsamic or black chinese vinegar and thinly sliced ginger. Soy sauce, chili oil or sesame oil may also be added to the dipping sauce."]'::jsonb),
  (640275, 'Crab Cakes Eggs Benedict', 'Crab Cakes Eggs Benedict requires around 30 minutes from start to finish.  One portion of this dish contains roughly 42g of protein, 59g of fat, and a total of 899 calories.', 'https://img.spoonacular.com/recipes/640275-312x231.jpg', 'https://www.foodista.com/recipe/P53KDVS3/crab-cakes-eggs-benedict', 30, 3, '{}'::text[], array['breakfast']::text[], '[{"name":"celery","amount":0.5,"unit":"cups","original":"1/2 cup finely chopped celery"},{"name":"bread crumbs","amount":0.33333334,"unit":"cups","original":"1/3 cup fine dry bread crumbs"},{"name":"eggs","amount":4,"unit":"","original":"4 Eggs"},{"name":"muffins","amount":3,"unit":"","original":"3 English Muffins"},{"name":"knorr hollandaise sauce mix","amount":1,"unit":"pkg","original":"1 package Knorr Hollandaise Sauce Mix"},{"name":"hot sauce","amount":3,"unit":"drops","original":"3 drops hot sauce"},{"name":"lump crab meat","amount":1,"unit":"lb","original":"1 pound lump crab meat"},{"name":"mayonnaise","amount":0.5,"unit":"cups","original":"1/2 cup mayonnaise"},{"name":"onion","amount":0.5,"unit":"cups","original":"1/2 cup finely chopped onion"},{"name":"parsley","amount":2,"unit":"Tbsps","original":"2 tablespoons minced parsley"},{"name":"seafood seasoning","amount":0.5,"unit":"tsps","original":"1/2 teaspoon seafood seasoning"},{"name":"butter","amount":6,"unit":"Tbsps","original":"6 tablespoons unsalted butter"},{"name":"worcestershire sauce","amount":0.5,"unit":"tsps","original":"1/2 teaspoon Worcestershire sauce"}]'::jsonb, '["Prepare the crab cakes:Cook onion and celery in 4 tablespoons butter over moderately low heat, until tender and transfer to a bowl. Stir in crab and bread crumbs.In a small bowl whisk together mayonnaise, seafood seasoning, Worcestershire sauce, hot sauce, parsley, and salt and pepper to taste and stir into crab mixture until combined well.Line a baking sheet with wax paper. Form crab mixture into 6 flattened rounds. Chill crab cakes, covered with plastic wrap, at least 1 hour.","Heat 1 tablespoon butter over moderate heat until foam subsides and cook half of crab cakes until golden brown, about 2 to 3 minutes on each side. Cook remaining cakes in remaining tablespoon butter in same manner.Prepare Knorr Hollandaise Sauce according to package instructions.Poach the eggs:Fill a medium sized sauce pan half way with water.","Add 1/2 teaspoon of white vinegar (this is optional but the vinegar helps hold the egg together). Bring to a gentle boil and carefully add eggs (1-2 at a time works best). Poach eggs for 2-3 minutes or until yolk has set to your preference.","Layer ingredients as follows: English muffin, crab cakes (1 each muffin), eggs, Hollandaise sauce."]'::jsonb),
  (715381, 'Creamy Lime Pie Square Bites', 'Creamy Lime Pie Square Bites might be just the dessert you are searching for.  One serving contains 631 calories, 8g of protein, and 33g of fat.', 'https://img.spoonacular.com/recipes/715381-312x231.jpg', 'https://www.pinkwhen.com/creamy-lime-pie-square-bites/', 45, 2, '{}'::text[], array['dessert']::text[], '[{"name":"all purpose flour","amount":0.6666667,"unit":"cups","original":"2/3 cup all purpose flour"},{"name":"graham cracker crumbs","amount":1,"unit":"cup","original":"1 cup crushed graham cracker crumbs"},{"name":"lime zest","amount":2,"unit":"drop","original":"2 drop Lime essential oil (this is the brand I use) OR if not using essential oils, use 1 Tbsp grated lime zest."},{"name":"sugar","amount":2,"unit":"Tbsps","original":"2 tbsp sugar"},{"name":"butter","amount":5,"unit":"Tbsps","original":"5 Tbsp unsalted butter (softened)"}]'::jsonb, '["Preheat oven to 35","Cover an 88 glass square dish with foil.","Whisk together all of your crust ingredients until it becomes a grainy consistency. Take a spoon and press the graham crust into the foil making sure all of the edges and bottom are completely covered.","Place into the oven and bake for 10-15 minutes until browned.","Remove from oven and allow to cool for about an hour.For the filling, add all of your ingredients into a medium bowl and mix well for about 30 minutes, and then for 3 minutes on low.","Place into the graham cracker crust, making sure all of the edges are filled.","Bake in the oven for about 5-10 minutes, and then remove.","Place onto a cooling rack for about 15 minutes, and then chill in the refrigerator for remaining 45 minutes to set.To serve, remove carefully from dish with foil and cut into bite sized squares.Looking for other ways to use Lime Essential Oil? A great group of bloggers and myself got together so we could share our favorite recipes to use with Lime. You dont have to use essential oils in order to make this delicious dessert, but if you have on hand, give it a try! You can find all of the other great Lime recipes below. Leave me a comment if you make these Creamy Lime Pie Square Bites and tell me if you love them as much as we do!If you have ever wanted to start using essential oils, you can read all about WHY I love to use mine here. Want to use Lime in a few different recipes? Check these additional recipes out.Coconut Lime Spritzer // Blackberry Lime Margaritas // Strawberry Limeade","Cherry Lime Chia Energy Bars // Strawberry Margarita Cheesecake // Creamy Lime Pie Bites","Margarita Crepe Cake //Edible Watermelon Bowl // Margarita Cookies","Southwestern Black Bean & Corn Salad // Lime Cheesecake Shooters","Not all essential oils are edible. Due to lack of purity, 98% of essential oils sold should NOT be ingested. An edible essential oil will be labeled therapeutic-grade and have a Supplement Facts box on the label showing the nutritional value  do NOT use just any brand of essential oil for cooking/flavoring foods. Be sure to use pure oils from reliable sources, not synthetic scents or flavorings.JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (775585, 'Crockpot "Refried" Beans', 'The recipe Crockpot "Refried" Beans can be made in around 45 minutes.  This recipe serves 16.', 'https://img.spoonacular.com/recipes/775585-312x231.jpg', 'http://penniesandpancakes.blogspot.com/2012/09/crockpot-refried-beans-019-per-cup.html?m=1', 45, 16, '{}'::text[], array['snack']::text[], '[{"name":"pepper","amount":1,"unit":"tsp","original":"1 tsp black pepper"},{"name":"cumin","amount":2,"unit":"tsps","original":"2 tsp cumin"},{"name":"garlic","amount":4,"unit":"Tbsps","original":"4 Tbsp. jarred minced garlic"},{"name":"onion","amount":1,"unit":"large","original":"1 large onion, chopped"},{"name":"pinto beans","amount":2,"unit":"lb","original":"2 lbs pinto beans"},{"name":"up salt","amount":1,"unit":"Tbsp","original":"*Up to 2 1/2 Tbsp salt (This is the absolute max if you don''t pre-soak your beans.)"},{"name":"water","amount":10,"unit":"cups","original":"10 cups hot water"}]'::jsonb, '["Rinse the beans in a colander. Pick out any bad beans.","Combine all the ingredients in the crockpot.","Remove any floating beans. Cover, and cook on HIGH for 4 hours and on LOW for 2 hours.Uncover, and remove extra liquid. Leave enough liquid to reach the desired consistency when the beans are mashed. (We like our beans somewhere between the very-liquidy restaurant style beans, and the canned version of refried beans.)Mash beans with a potato masher to desired consistency.","Serve warm. Store in air-tight containers in the refrigerator and use within 2 weeks, or freeze in ziplock bags for later use."]'::jsonb),
  (715452, 'Delicious Triple Chocolate Bundt Cake', 'Delicious Triple Chocolate Bundt Cake might be a good recipe to expand your dessert recipe box.  This recipe makes 6 servings with 582 calories, 5g of protein, and 30g of fat each.', 'https://img.spoonacular.com/recipes/715452-312x231.jpg', 'https://www.pinkwhen.com/delicious-triple-chocolate-bundt-cake/', 55, 6, '{}'::text[], array['dessert']::text[], '[{"name":"devil''s food cake mix","amount":1,"unit":"","original":"1 devil''s food cake mix"},{"name":"chocolate fudge pudding mix","amount":1,"unit":"small","original":"1 small box chocolate fudge pudding mix"},{"name":"milk chocolate chips","amount":1,"unit":"cup","original":"1 cup milk chocolate chips"},{"name":"cream","amount":1,"unit":"cup","original":"1 cup sour cream"}]'::jsonb, '["Preheat your oven to 350 degrees.","Mix the cake as directed.","Add the pudding and sour cream.","Mix well. Stir in chocolate chips.Spray a bundt pan generously with non-stick spray and then coat with flour.","Bake for 50 minutes. Cool for 5 minutes and dump onto the cooling rack.Optional: serve warm sliced with a drizzle of Dove milk chocolate ice cream topping and a scoop of vanilla ice cream."]'::jsonb),
  (641461, 'Deviled Eggs With Crab', 'Deviled Eggs With Crab requires roughly 45 minutes from start to finish.  One serving contains 120 calories, 10g of protein, and 8g of fat.', 'https://img.spoonacular.com/recipes/641461-312x231.jpg', 'https://www.foodista.com/recipe/SG5QX2ZK/deviled-eggs-with-crab', 45, 6, array['American']::text[], array['snack']::text[], '[{"name":"celery","amount":0.5,"unit":"stick","original":"1/2 stick celery, finely chopped"},{"name":"dijon mustard","amount":1,"unit":"Tbsp","original":"1 tablespoon Dijon mustard"},{"name":"hardboiled eggs","amount":6,"unit":"","original":"6 hard boiled eggs, peeled, halved, and yolks removed"},{"name":"chives","amount":3,"unit":"Tbsps","original":"3 tablespoons chopped fresh chives"},{"name":"lemon juice","amount":1,"unit":"Tbsp","original":"1 tablespoon fresh lemon juice"},{"name":"lump crabmeat","amount":4,"unit":"oz","original":"4 ounces lump crabmeat"},{"name":"mayonnaise","amount":1,"unit":"Tbsp","original":"1 tablespoon mayonnaise"},{"name":"salt and pepper","amount":6,"unit":"servings","original":"Salt and freshly ground black pepper"},{"name":"cream","amount":2,"unit":"Tbsps","original":"2-3 tablespoons sour cream"}]'::jsonb, '["In a medium-sized mixing bowl combine the crabmeat, celery, sour cream, mayonnaise, Dijon mustard, lemon juice, and chives. Stir until well combined.Season, to taste, with salt and pepper.Spoon the crab mixture into the egg halves.","Serve immediately or chilled until ready."]'::jsonb),
  (641893, 'Easy Cheesy Pizza Casserole', 'You can never have too many Mediterranean recipes, so give Easy Cheesy Pizza Casserole a try.  This main course has 902 calories, 57g of protein, and 55g of fat per serving.', 'https://img.spoonacular.com/recipes/641893-312x231.jpg', 'https://www.foodista.com/recipe/ZTHZWCWF/easy-cheesy-pizza-casserole', 45, 6, array['Mediterranean', 'Italian', 'European']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"equivalent amount of a ground beef/bulk sausage mix","amount":1,"unit":"lb","original":"1 lb ground beef or equivalent amount of a ground beef/bulk Italian sausage mix"},{"name":"ricotta","amount":0.5,"unit":"cups","original":"1/2 cup ricotta"},{"name":"oregano","amount":1,"unit":"pinch","original":"pinch of oregano"},{"name":"basil","amount":1,"unit":"pinch","original":"pinch of basil"},{"name":"parmesan cheese","amount":1,"unit":"Tbsp","original":"1 Tbs grated Parmesan cheese"},{"name":"pasta sauce","amount":26,"unit":"oz","original":"1 - 26 oz jar of pasta sauce"},{"name":"pizza sauce","amount":1,"unit":"can","original":"1 can pizza sauce"},{"name":"pepper flakes","amount":0.125,"unit":"tsps","original":"1/8 - 1/2 tsp crushed red pepper flakes"},{"name":"pepperoni","amount":0.5,"unit":"","original":"Pepperoni slices (I used 1/2 of a package of Hormel brand)"},{"name":"mozzarella","amount":2,"unit":"cups","original":"2 cups shredded mozzarella"},{"name":"aged provolone","amount":0.5,"unit":"cups","original":"1/2 cup shredded aged Provolone"},{"name":"herbed parmesan drop biscuits","amount":6,"unit":"servings","original":"Herbed Parmesan Drop Biscuits"},{"name":"additional parmesan cheese","amount":6,"unit":"servings","original":"Additional Parmesan cheese for topping"},{"name":"baking mix","amount":2.25,"unit":"cups","original":"2 1/4 cup baking mix (like Bisquick or Jiffy)"},{"name":"parmesan cheese","amount":0.25,"unit":"cups","original":"1/4 cup grated Parmesan cheese"},{"name":"seasoning","amount":1,"unit":"tsp","original":"1 tsp Italian seasoning"},{"name":"milk","amount":0.6666667,"unit":"cups","original":"2/3 cup milk"},{"name":"or","amount":1,"unit":"serving","original":"-or-"},{"name":"or","amount":6,"unit":"servings","original":"-or-"}]'::jsonb, '["Brown ground beef in skillet; drain fat.","Mix in pasta or pizza sauce and pepper flakes; set aside.","Mix ricotta cheese with the herbs and Parmesan in a separate bowl; set aside.","Mix the dry ingredients for the biscuits.","Add milk and stir until combined.","Preheat oven to 375 degrees.  Spray a 13 x 9 pan with non-stick spray.  Drop biscuit dough by teaspoons in the bottom of pan, spacing evenly.  It''s OK if there is space between the dough--it will expand as it''s cooked.  Top with ground beef mixture and dot with the ricotta cheese mixture.","Bake at 375 for about 20 min or until biscuits are puffed and beginning to get golden brown.","Top with mozzarella and provolone cheeses and distribute pepperoni slices evenly over top, increase oven temperature to 425 degrees.  Return to oven and bake until cheeses are melted and beginning to bubble.  This should take about 10 minutes.","Remove from oven and let stand 5 minutes before slicing and serving.  May be topped with the additional Parmesan cheese."]'::jsonb),
  (641908, 'Easy Chicken Tikka Masala', 'Easy Chicken Tikka Masala might be a good recipe to expand your main course recipe box.  One serving contains 371 calories, 38g of protein, and 20g of fat.', 'https://img.spoonacular.com/recipes/641908-312x231.jpg', 'https://www.foodista.com/recipe/7Q3RC88N/easy-chicken-tikka-masala', 45, 4, array['Indian', 'Asian']::text[], array['lunch', 'dinner']::text[], '[{"name":"chicken breasts","amount":3,"unit":"","original":"3 chicken breasts cut into bite size cubes"},{"name":"grape seed oil","amount":4,"unit":"Tbsps","original":"4 tablespoons of vegetable oil or grape seed oil"},{"name":"onion","amount":1,"unit":"large","original":"1 large onion chopped"},{"name":"garlic","amount":2,"unit":"cloves","original":"2 cloves of garlic finely chopped"},{"name":"garam masala","amount":1,"unit":"tsp","original":"1 teaspoon garam masala (spice mixture)"},{"name":"cumin","amount":1,"unit":"tsp","original":"1 teaspoon cumin"},{"name":"coriander","amount":1,"unit":"tsp","original":"1 teaspoon coriander"},{"name":"turmeric","amount":0.25,"unit":"tsps","original":"1/4 teaspoon turmeric"},{"name":"cardamon","amount":0.125,"unit":"tsps","original":"1/8 teaspoon cardamon"},{"name":"cinnamon","amount":0.25,"unit":"tsps","original":"1/4 teaspoon cinnamon"},{"name":"ginger","amount":2,"unit":"tsps","original":"2 teaspoons fresh ginger, finely chopped"},{"name":"cayenne","amount":0.5,"unit":"tsps","original":"1/2 teaspoon cayenne"},{"name":"paprika","amount":1,"unit":"Tbsp","original":"1 tablespoon paprika"},{"name":"tomato paste","amount":1,"unit":"tsp","original":"1 teaspoon tomato paste"},{"name":"tomato","amount":1,"unit":"","original":"1 tomato chopped"},{"name":"water","amount":0.5,"unit":"cups","original":"1/2 cup water"},{"name":"yogurt","amount":0.5,"unit":"cups","original":"1 small container plain yogurt (about ½ cup)"},{"name":"coriander","amount":4,"unit":"servings","original":"fresh coriander for garnish"},{"name":"salt","amount":4,"unit":"servings","original":"Salt to taste"}]'::jsonb, '["In a small bowl mix all the spices including the ginger. Set aside.","In a large saucepan, heat the oil .","Add the onions and cook until golden brown.","Add the garlic and continue to cook for a minute.","Stir in the spices and allow the flavours to infuse.","Stir in the tomato paste.","Add the chopped tomato and pour in the water. Simmer and season with salt to taste.","Add the chicken pieces stirring well to coat the meat with the sauce. Continue to simmer until the chicken is cooked and the sauce has thickened, about 12 minutes.","Stir in the yogurt and continue to simmer 5 minutes.","Garnish with chopped fresh cilantro","Serve with bismati rice."]'::jsonb),
  (775666, 'Easy Homemade Apple Fritters', 'Easy Homemade Apple Fritters might be just the breakfast you are searching for.  One portion of this dish contains approximately 2g of protein, 1g of fat, and a total of 148 calories.', 'https://img.spoonacular.com/recipes/775666-312x231.jpg', 'https://www.recipeoftoday.com/2015/05/easy-homemade-apple-fritters.html?m=1', 30, 12, '{}'::text[], array['breakfast']::text[], '[{"name":"all purpose flour","amount":1,"unit":"cup","original":"1 cup all purpose flour"},{"name":"apple","amount":1,"unit":"cup","original":"1 cup chopped apple"},{"name":"baking powder","amount":1.5,"unit":"tsps","original":"1 1/2 teaspoons baking powder"},{"name":"cinnamon","amount":1,"unit":"tsp","original":"1 teaspoon cinnamon"},{"name":"egg","amount":1,"unit":"","original":"1 egg"},{"name":"milk","amount":0.33333334,"unit":"cups","original":"1/3 cup milk"},{"name":"milk","amount":1.5,"unit":"Tbsps","original":"1 1/2 tablespoons milk"},{"name":"powdered sugar","amount":2,"unit":"cups","original":"2 cups powdered sugar"},{"name":"salt","amount":0.75,"unit":"tsps","original":"3/4 teaspoon salt"},{"name":"sugar","amount":0.25,"unit":"cups","original":"1/4 cup sugar"}]'::jsonb, '["Combine flour, sugar, salt, baking powder, cinnamon. Stir in milk and egg until just combined. Fold in apple.","Pour oil into skillet so that it is approximately 1 1/2 deep.","Heat oil on high. Oil is ready when a little dough thrown in floats to top. Carefully add dough to oil in heaping teaspoons. Cook until brown, about 2 minutes, then flip. Cook another 1-2 minutes, until both sides are browned.","Transfer briefly to paper towels to absorb excess oil, then transfer to cooling rack. Make glaze by stirring milk and powdered sugar together in a small bowl.","Drizzle over apple fritters. Wait approximately 3 minutes for glaze to harden, then flip fritters and drizzle glaze over the other side. Best served warm."]'::jsonb),
  (642138, 'Easy Vegetable Fried Rice', 'The recipe Easy Vegetable Fried Rice can be made in approximately 20 minutes.  This hor d''oeuvre has 236 calories, 7g of protein, and 10g of fat per serving.', 'https://img.spoonacular.com/recipes/642138-312x231.jpg', 'https://www.foodista.com/recipe/H78BYQPP/easy-vegetable-fried-rice', 20, 4, array['Chinese', 'Asian']::text[], array['snack']::text[], '[{"name":"broccoli","amount":1,"unit":"cup","original":"1 cup broccoli"},{"name":"butter","amount":1,"unit":"Tbsp","original":"1 tbsp butter"},{"name":"carrots","amount":0.33333334,"unit":"cups","original":"1/3 cup thinly sliced carrots"},{"name":"rice","amount":2,"unit":"cups","original":"2 cups cooked rice"},{"name":"egg","amount":1,"unit":"","original":"1 egg"},{"name":"garlic","amount":1,"unit":"clove","original":"1 clove garlic, minced"},{"name":"ginger","amount":1,"unit":"Tbsp","original":"1 tbsp minced ginger"},{"name":"green beans","amount":0.5,"unit":"cups","original":"½ cup green beans"},{"name":"peas","amount":0.5,"unit":"cups","original":"½ cup peas"},{"name":"sesame oil","amount":1.5,"unit":"Tbsps","original":"1 ½ tbsp sesame oil"},{"name":"soy sauce","amount":4,"unit":"servings","original":"soy sauce to taste"},{"name":"sugar","amount":1,"unit":"dash","original":"dash of sugar"}]'::jsonb, '["First blanch the raw green vegetables by sticking them in a pot of boiling water for a couple of minutes and then draining them. If you''re using frozen vegetables, follow the package cooking instructions, but stop shy of three minutes of cooking time so they don''t get mushy.In large pan or wok, heat your sesame oil over medium heat. Throw in the garlic and ginger and fry that up for about a minute.","Add the carrots and stir quickly for a minute or two. Then add the rice.Now add soy sauce based on your saltiness preference.","Let that sizzle while you whip your egg in a small bowl. Move your rice to the edges of the pan so you have an empty space in the middle.","Add the egg and scramble it up. When it looks close to being cooked, stir the rice back into the middle of the pan.Next, throw in the broccoli and peas or other blanched vegetables of your choice.","Add the sugar and stir for a couple minutes, then add the butter. Once the butter is melted through, let the rice sit there.","Let it sizzle a bit.That''s it!","Serve your fried rice."]'::jsonb),
  (716202, 'Fenugreek Roti', 'Fenugreek Roti requires roughly 45 minutes from start to finish.  This bread has 80 calories, 4g of protein, and 2g of fat per serving.', 'https://img.spoonacular.com/recipes/716202-312x231.jpg', 'https://www.foodandspice.com/2012/07/fenugreek-roti.html', 45, 10, array['Indian', 'Asian']::text[], '{}'::text[], '[{"name":"ajwain seeds","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ajwain seeds"},{"name":"asafetida","amount":1,"unit":"pinch","original":"pinch of asafetida"},{"name":"baking soda","amount":0.25,"unit":"tsps","original":"1/4 teaspoon baking soda"},{"name":"cayenne","amount":0.5,"unit":"tsps","original":"1/2 teaspoon cayenne"},{"name":"chickpea flour","amount":1,"unit":"cup","original":"1 cup chickpea flour (besan)"},{"name":"chili powder","amount":0.5,"unit":"tsps","original":"1/2 teaspoon chili powder"},{"name":"fenugreek leaves","amount":0.5,"unit":"cups","original":"1/2 cup dried fenugreek leaves"},{"name":"ghee","amount":10,"unit":"servings","original":"ghee or oil for frying"},{"name":"ground coriander","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground coriander"},{"name":"ground cumin","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground cumin"},{"name":"yogurt","amount":2,"unit":"Tbsps","original":"2 tablespoons plain yogurt"},{"name":"sea salt","amount":1,"unit":"tsp","original":"1 teaspoon sea salt"},{"name":"flour","amount":0.5,"unit":"cups","original":"1/2 cup whole wheat flour"}]'::jsonb, '["Soak the dried fenugreek leaves in warm water for 5 to 10 minutes.","Drain, making sure to squeeze out excess liquid.Sift the flours and baking soda in a small strainer into a medium bowl. Stir in the salt, chili powder, cayenne, cumin, coriander, ajwain seeds, asafetida, yogurt and fenugreek leaves.","Mix in about 1/4 cup of water to make a semi-hard batter. Cover and let stand at room temperature for 1 hour. Dusting your hands with flour, divide the dough into 10 to 12 small balls.","Roll out each ball into a roughly 3-inch circle.","Brush a non-stick pan with a bit of ghee or oil and heat over medium heat. When hot, add a rolled out portion to the pan and cook for 4 minutes or until the bottom is browned.","Sprinkle with a bit of oil, flip and fry for another 2 to 3 minutes or until both sides are browned.","Transfer to a plate, keep heated in a 150 oven, and repeat for the rest of the pancakes."]'::jsonb),
  (644081, 'Fudgy chocolate cream cheese brownies with Baileys', 'Fudgy chocolate cream cheese brownies with Baileys takes approximately 45 minutes from beginning to end.  This dessert has 586 calories, 7g of protein, and 34g of fat per serving.', 'https://img.spoonacular.com/recipes/644081-312x231.jpg', 'https://www.foodista.com/recipe/6DCLS47W/fudgy-chocolate-cream-cheese-brownies-with-baileys', 45, 8, array['American']::text[], array['dessert']::text[], '[{"name":"bittersweet chocolate","amount":8,"unit":"oz","original":"8 oz bittersweet chocolate, chopped"},{"name":"butter","amount":0.5,"unit":"cups","original":"1/2 cup butter, room temperature"},{"name":"cream cheese","amount":8,"unit":"oz","original":"1 package cream cheese (8 oz), room temperature"},{"name":"eggs","amount":3,"unit":"large","original":"3 large eggs, at room temperature"},{"name":"flour","amount":0.75,"unit":"cups","original":"3/4 cups All-purpose flour"},{"name":"espresso","amount":1,"unit":"Tbsp","original":"1 tablespoon instant espresso"},{"name":"sugar","amount":1.5,"unit":"cups","original":"1 1/2 cup sugar"},{"name":"vanilla extract","amount":1,"unit":"Tbsp","original":"1 tablespoon vanilla extract"},{"name":"baileys","amount":2,"unit":"Tbsps","original":"2 tablespoon Baileys"},{"name":"baileys","amount":2,"unit":"Tbsps","original":"2 tablespoon Baileys"}]'::jsonb, '["To make the chocolate layer, place chocolate and butter in a large glass dish (you will be adding the eggs, sugar, and flour to it later) and microwave 1.5 minutes. The chocolate may hold its shape when you remove it from the microwave, but it will be soft, so stir to melt it. If pieces remain after you have stirred it for a while then return to microwave for another few seconds and then stir again until it is fully melted. Be careful not to overheat the chocolate. You are better off starting with less time and reheating than overheating and ruining it.When chocolate has melted add the sugar and vanilla and stir with a whisk to combine.","Let it cool a little and then add the eggs, one at a time, whisking after each addition. Don''t add the eggs when the chocolate is hot because it may cook the whites.Once the eggs are mixed in, place the flour in a strainer and sift over the chocolate mixture, a little at a time, mixing it in as you sift it over. Set aside while you prepare the cream cheese layer.For the cream cheese layer, place the cream cheese in a bowl and mix with a hand mixer for a couple of minutes until soft.","Add the sugar and mix to blend it in.","Add egg and beat to incorporate.","Add Bailey''s and stir it in.To assemble, spray an 8\" square baking pan with straight sides with non-stick spray, or butter and flour it. You can also line the baking pan with parchment, leaving the edges high so you can lift the entire cake out of the pan.","Pour the chocolate mixture into the pan and tilt it to spread it out evenly.","Pour the cream cheese mixture over it, and with a fork, swirl the layers so some of the chocolate shows on top and the cream cheese layer becomes part of the chocolate layer. Do not over mix - you just want some swirls.","Place in a preheated 350 degree F oven and bake for 35 minutes or until a knife inserted into the center comes out clean. Do not over bake.","Remove from oven and let cool before cutting into squares."]'::jsonb),
  (644376, 'Garlic-Butter Naan', 'You can never have too many Indian recipes, so give Garlic-Butter Naan a try.  One serving contains 462 calories, 10g of protein, and 22g of fat.', 'https://img.spoonacular.com/recipes/644376-312x231.jpg', 'https://www.foodista.com/recipe/6BPCGSNT/garlic-butter-naan', 45, 4, array['Indian', 'Asian']::text[], array['snack']::text[], '[{"name":"ice water","amount":0.5,"unit":"cups","original":"1/2 c. ice water"},{"name":"nonfat greek yogurt","amount":0.33333334,"unit":"cups","original":"1/3 c. nonfat greek yogurt"},{"name":"canola oil","amount":0.25,"unit":"cups","original":"1/4 c. canola oil, plus 1 t. for cooking the naan"},{"name":"egg yolk","amount":1,"unit":"large","original":"1 large egg yolk"},{"name":"flour","amount":2.25,"unit":"cups","original":"2 1/4 c. flour"},{"name":"sugar","amount":0.438,"unit":"tsps","original":"1 1/4 t. sugar"},{"name":"rapid-rise yeast","amount":0.389,"unit":"tsps","original":"1/2 t. instant or rapid-rise yeast"},{"name":"salt","amount":0.25,"unit":"tsps","original":"3/4 t. salt"},{"name":"butter","amount":2.029,"unit":"Tbsps","original":"2 T. butter"},{"name":"garlic","amount":1,"unit":"clove","original":"1 clove garlic, minced"}]'::jsonb, '["In a small bowl, mix together water, yogurt, 1/4 c. oil and egg yolk. In the workbowl of a food processor, pulse together flour, sugar and yeast to combine. With the motor running, slowly add the liquid ingredients to the flour. Process until combined.","Let mixture rest for 10 minutes.","Add salt and process another 30-60 seconds. It will form a sticky dough that should clear the sides of the food processor workbowl.","Scrape dough out onto a floured worksurface and knead just until smooth, about a minute. Form into a ball and place in a lightly oiled bowl (large). Cover tightly with plastic wrap and refrigerate 16-24 hours.","After the dough has rested, turn out onto a lightly floured work surface and divide dough into 4 pieces and shape each piece into a ball. Cover lightly with plastic wrap and let rest 15-20 minutes.","Meanwhile melt the butter in a small saucepan, then add the garlic. Set aside.","Roll the first piece of dough out into a 9 inch round. Using a fork, poke the dough all over, 20-25 times. Lightly mist the top side with water.","Heat the remaining oil in a large nonstick skillet over medium heat until the oil begins to shimmer. Wipe the oil out of the skillet with paper towels, then add the rolled out dough, sprayed side down and spray the other side lightly. Cover skillet and cook until spotty brown underneath, 2-4 minutes (poke any large bubbles that form). Flip naan, cook, covered, another 2-3 minutes until browned. Flip again, brush with butter, then transfer to a plate and cover with foil. While rolling out and cooking the remaining naan."]'::jsonb),
  (716408, 'Greek-Style Baked Fish: Fresh, Simple, and Delicious', 'Greek-Style Baked Fish: Fresh, Simple, and Delicious might be just the Mediterranean recipe you are searching for.  For $3.', 'https://img.spoonacular.com/recipes/716408-312x231.jpg', 'https://fullbellysisters.blogspot.com/2012/04/greek-style-baked-fish-fresh-simple-and.html', 30, 4, array['Mediterranean', 'European', 'Greek']::text[], array['lunch', 'dinner']::text[], '[{"name":"bell pepper","amount":1,"unit":"","original":"1 bell pepper"},{"name":"rice","amount":4,"unit":"servings","original":"Cooked rice, for serving"},{"name":"basil","amount":1,"unit":"tsp","original":"1 tsp Dried basil"},{"name":"feta cheese","amount":2,"unit":"oz","original":"2 – 3 oz. of crumbled feta cheese per pound of fish"},{"name":"fish fillets","amount":1,"unit":"lb","original":"1 lb fish fillets"},{"name":"olive oil","amount":2,"unit":"Tbsps","original":"2 Tablespoons olive oil per pound of fish"},{"name":"oregano","amount":1,"unit":"tsp","original":"1 tsp dried oregano"},{"name":"pepper","amount":4,"unit":"servings","original":"Freshly ground pepper"},{"name":"onion","amount":0.5,"unit":"","original":"1/2 Red onion"},{"name":"salt & pepper","amount":4,"unit":"servings","original":"Salt & pepper"},{"name":"tomato","amount":1,"unit":"","original":"1 tomato"},{"name":"white wine","amount":0.25,"unit":"cups","original":"¼ cup white wine"}]'::jsonb, '["Preheat the oven to 450 degrees F. Choose an oven-proof baking dish that your fish will fit in without overlapping and spray it with cooking spray.","Lay the fish fillets in the baking pan in a single layer, season with salt and pepper, then top the fish with red onion and bell pepper.","Sprinkle with dried basil and oregano, the tomato, and the feta cheese, then drizzle the white wine and olive oil over top. Grind some fresh pepper over the top.","Bake uncovered for about 12 – 15 minutes or until the fish flakes easily with a fork. Squeeze the lemon wedges over the cooked fish, garnish with the fresh basil and/or oregano and serve with hot cooked rice."]'::jsonb),
  (645541, 'Green Thai Curry with Beef', 'Green Thai Curry with Beef might be a good recipe to expand your main course recipe box.  For $5.', 'https://img.spoonacular.com/recipes/645541-312x231.jpg', 'https://www.foodista.com/recipe/XLCRNHRG/green-thai-curry-with-beef', 180, 4, array['Thai', 'Asian']::text[], array['lunch', 'dinner']::text[], '[{"name":"baby bok choy","amount":4,"unit":"oz","original":"4 oz baby bok choy (trimmed)"},{"name":"coconut milk","amount":1,"unit":"can","original":"1 can coconut milk"},{"name":"carrots","amount":2,"unit":"large","original":"2 large carrots (thinly sliced diagonal)"},{"name":"curry powder","amount":2,"unit":"Tbsps","original":"2 tbsp. green curry powder"},{"name":"fish sauce","amount":2,"unit":"Tbsps","original":"2 tbsp. fish sauce"},{"name":"flank steak","amount":20,"unit":"oz","original":"20 oz. flank steak"},{"name":"garlic","amount":2,"unit":"cloves","original":"2 cloves of garlic (thinly sliced)"},{"name":"lemon juice","amount":1,"unit":"Tbsp","original":"1 tbsp. lemon juice"},{"name":"ground lemongrass","amount":0.5,"unit":"tsps","original":"1/2 tsp. ground lemongrass"},{"name":"oil","amount":4,"unit":"servings","original":"Oil for cooking in wok"},{"name":"onions","amount":1,"unit":"large","original":"1 large onions (sliced)"},{"name":"orange pepper","amount":1,"unit":"","original":"1 orange pepper (thinly sliced)"},{"name":"oyster mushrooms","amount":7,"unit":"oz","original":"7oz. oyster mushrooms (chopped)"},{"name":"bell pepper","amount":1,"unit":"","original":"1 red pepper (thinly sliced)"},{"name":"rice wine vinegar","amount":1,"unit":"Tbsp","original":"1 tbsp. rice wine vinegar"},{"name":"snap peas","amount":4,"unit":"oz","original":"4 oz. snap peas (thinly sliced diagonal)"},{"name":"soy sauce","amount":3,"unit":"Tbsps","original":"3 tbsp. soy sauce"},{"name":"bell pepper","amount":1,"unit":"","original":"1 yellow pepper (thinly sliced)"}]'::jsonb, '["Prepare marinade.Slice beef.","Add beef and marinade to freezer bag. Marinate for 2-4 in the fridge. The longer the better.Slice/chop all your veggies.Prepare your curry paste.","Add oil to wok and heat.Cook beef until done, approximately 10 minutes.","Remove from wok and set aside.","Add onions and cook for about 2 minutes.","Add carrots, peppers and mushrooms.When almost done (to your preferred tenderness) add snap peas and bok choy. Cook about 2 minutes.","Remove veggies from wok and set aside.","Add curry paste to wok and heat through.","Add coconut milk and whisk until smooth.Bring to a boil.","Add beef to the sauce.","Add veggies to the beef/sauce mixture.","Heat through.","Serve over your choice of noodles or riice."]'::jsonb),
  (715595, 'How to Make the Cheesiest Bowtie Mac and Cheese', 'How to Make the Cheesiest Bowtie Mac and Cheese might be just the main course you are searching for.  This recipe serves 4 and costs $1.', 'https://img.spoonacular.com/recipes/715595-312x231.jpg', 'https://www.pinkwhen.com/mac-and-cheese-recipe/', 35, 4, array['American']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"bowtie pasta cook as directed","amount":1,"unit":"pkg","original":"1 package of Bowtie pasta cook as directed"},{"name":"extra sharp cheddar cheese","amount":1,"unit":"cup","original":"1 cup Extra Sharp Cheddar cheese"},{"name":"extra sharp cheddar cheese","amount":1,"unit":"cup","original":"1 cup Extra Sharp White Cheddar cheese"},{"name":"salt and pepper","amount":1,"unit":"tsp","original":"1 tsp salt and pepper"},{"name":"cream","amount":0.25,"unit":"cups","original":"1/4 cup sour cream"},{"name":"butter","amount":0.25,"unit":"cups","original":"1/4 cup unsalted butter room temperature"},{"name":"parsley","amount":4,"unit":"servings","original":"Fresh Parsley for garnish"}]'::jsonb, '["Heat your oven to 350 degrees Fahrenheit, and then cook your pasta as directed.","Drain.","Shred the cheese.","Add cooked noodles, cheese, sour cream, salt and pepper, and butter to a medium mixing bowl and stir until combined.","Add to a 9 x 13 prepared casserole dish, top with extra cheese if desired, and bake for 20 minutes.","Remove from oven and serve hot."]'::jsonb),
  (716311, 'Mango Fried Rice', 'Mango Fried Rice is a Chinese main course.  This recipe makes 2 servings with 486 calories, 16g of protein, and 4g of fat each.', 'https://img.spoonacular.com/recipes/716311-312x231.jpg', 'https://www.afrolems.com/2015/05/02/mango-fried-rice/', 45, 2, array['Chinese', 'Asian']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"chicken stock","amount":2,"unit":"cups","original":"2 cups of chicken stock"},{"name":"seasoning cubes","amount":2,"unit":"servings","original":"Seasoning cubes"},{"name":"mango","amount":3,"unit":"slice","original":"3 slices of mango cubed"},{"name":"rice","amount":1,"unit":"cup","original":"1 cup of rice"},{"name":"vegetables","amount":1,"unit":"cup","original":"1 cup of chopped vegetables"},{"name":"scotch bonnet pepper","amount":1,"unit":"","original":"1 scotch bonnet pepper"}]'::jsonb, '["Wash your rice and bring to boil on medium heat with very little water as you are still going to cook it in chicken stock.Once the rice is slightly soft and the initial water has dried up, reduce the heat and pour in the chicken stock and cook till the chicken stock is all absorbed and has dried up. The chicken stock if freshly made will have some oil from the chicken so your rice does not need oil.Increase the heat and stir in the chopped vegetables and pepper.","Add your seasoning cube.Finally stir in your cubed mango and serve warm with any protein of your choice. I’d say chicken but it’s up to you."]'::jsonb),
  (652651, 'Mushroom Crepes with Vegetarian Sauce', 'You can never have too many breakfast recipes, so give Mushroom Crepes with Vegetarian Sauce a try.  This lacto ovo vegetarian recipe serves 8 and costs $1.', 'https://img.spoonacular.com/recipes/652651-312x231.jpg', 'https://www.foodista.com/recipe/LZFR2QTP/mushroom-crepes-with-vegan-vegetarian-sauce', 45, 8, array['Mediterranean', 'French', 'European']::text[], array['breakfast']::text[], '[{"name":"corn","amount":0.5,"unit":"cups","original":"½ cup canned corn"},{"name":"chives","amount":1,"unit":"Tbsp","original":"1-2 tbsp chopped chives"},{"name":"dill","amount":0.5,"unit":"cups","original":"1/2 cup chopped dill"},{"name":"eggs","amount":2,"unit":"","original":"2 eggs"},{"name":"garlic cloves","amount":2,"unit":"","original":"2-3 garlic cloves, mashed"},{"name":"garlic powder","amount":1,"unit":"tsp","original":"1 tsp garlic powder"},{"name":"ground coriander","amount":0.5,"unit":"tsps","original":"1/2 tsp ground coriander"},{"name":"ground pepper","amount":0.333,"unit":"tsps","original":"1/3 tsp ground pepper"},{"name":"cream","amount":0.5,"unit":"cups","original":"½ cup low fat sour cream"},{"name":"mushrooms","amount":10.582,"unit":"oz","original":"300g mushrooms"},{"name":"oil","amount":8,"unit":"servings","original":"Oil – for frying"},{"name":"big onion","amount":1,"unit":"","original":"1 big onion, chopped"},{"name":"parsley","amount":0.5,"unit":"cups","original":"1/2 cup chopped parsley"},{"name":"sea salt","amount":1,"unit":"pinch","original":"a pinch of sea salt"},{"name":"sea salt","amount":8,"unit":"servings","original":"sea salt, to taste"},{"name":"paprika","amount":1,"unit":"tsp","original":"1tsp sweet paprika"},{"name":"water","amount":1.057,"unit":"cups","original":"250 ml water"},{"name":"white wine","amount":0.5,"unit":"cups","original":"1/2 cup white wine"},{"name":"flour","amount":7.055,"unit":"oz","original":"200g whole wheat flour"}]'::jsonb, '["Whisk the eggs.","Add the water and mix well (you can also use a hand-held mixer).","Sprinkle the flour while continuously whisking/mixing until it has the right consistency.","Heat some oil in a frying pan over medium-high heat. Grease the whole surface of the pan and then pour the oil in a cup. You’ll be reusing it.","Add the mushrooms and wine in your food processor. Blend until you get a thick paste.","Heat some 1 tbsp oil in a large saucepan.","Add the chopped onion. Sauté until golden, then add the mushroom paste and corn.","Add spices.Cook for 15 minutes ten add the chopped dill and parsley and cook for another 5 minutes.","Mix last four ingredients and pour sauce over the vegetarian mushroom crepes."]'::jsonb),
  (716272, 'Nutella Crepes and Ice Cream', 'The recipe Nutella Crepes and Ice Cream could satisfy your Mediterranean craving in roughly 45 minutes.  For $1.', 'https://img.spoonacular.com/recipes/716272-312x231.jpg', 'https://www.afrolems.com/2013/12/19/nutella-crepes-and-ice-cream/', 45, 6, array['Mediterranean', 'French', 'European']::text[], array['dessert']::text[], '[{"name":"strawberries/ bananas","amount":6,"unit":"servings","original":"Strawberries/ bananas"},{"name":"butter","amount":1,"unit":"Tbsp","original":"1 tablespoon of melted butter or oil"},{"name":"butter milk","amount":1.25,"unit":"cups","original":"1 1/4 cup of butter milk (you can use any kind of milk available )"},{"name":"cinnamon","amount":0.5,"unit":"tsps","original":"1/2 teaspoon of cinnamon"},{"name":"eggs","amount":2,"unit":"","original":"2 eggs"},{"name":"flour","amount":1,"unit":"cup","original":"1 cup of flour"},{"name":"ice cream","amount":6,"unit":"servings","original":"Ice cream"},{"name":"nutella","amount":6,"unit":"servings","original":"Nutella"},{"name":"oil","amount":6,"unit":"servings","original":"Oil or butter (for frying)"},{"name":"sugar","amount":0.25,"unit":"cups","original":"1/4 cup of sugar"},{"name":"tea spoon of vanilla extract","amount":1,"unit":"","original":"1 tea spoon of vanilla extract"}]'::jsonb, '["In a dry clean bowl, mix together the dry ingredients (flour, sugar, cinnamon)In another bowl, break the eggs and whisk properly, add the milk, butter (or oil), vanilla extract and whisk properly.","Add the wet ingredients to the dry ingredients and whisk, ensuring that there are no lumps (Tip: you can use a blender in order to prevent lumps , and if normal whisk is used and you notice lumps you can sieve out the lumps)Grease (with oil or butter) a crepe pan or a big frying pan","Set to medium to low heat","Pour batter in the middle of pan and move pan around to ensure that the batter covers the entire pan ( the idea is to make the crepe as thin as possible so avoid pouring a lot of batter into the pan at once)Fry each side of the crepe for 3-4 minutes","Scoop Nutella into a bowl and microwave for 45 secs to soften it up, so that it doesn’t rip the crepes","Slice bananas or strawberry","Spread Nutella on one half of the crepe, put the strawberries/bananas and fold over"]'::jsonb),
  (715541, 'Pink Lemonade Crinkle Cookies', 'Pink Lemonade Crinkle Cookies might be a good recipe to expand your dessert recipe box.  This recipe serves 5.', 'https://img.spoonacular.com/recipes/715541-312x231.jpg', 'https://www.pinkwhen.com/pink-lemonade-crinkle-cookies/', 45, 5, '{}'::text[], array['dessert']::text[], '[{"name":"baking powder","amount":0.25,"unit":"tsps","original":"1/4 tsp Baking Powder"},{"name":"baking soda","amount":0.25,"unit":"tsps","original":"1/4 tsp Baking Soda"},{"name":"butter","amount":0.75,"unit":"cups","original":"3/4 C Butter"},{"name":"cornstarch","amount":0.5,"unit":"cups","original":"1/2 C Cornstarch"},{"name":"egg","amount":1,"unit":"","original":"1 Egg"},{"name":"flour","amount":1.5,"unit":"cups","original":"1 1/2 C All-Purpose Flour"},{"name":"pink food coloring","amount":1,"unit":"drop","original":"1 drop of pink food coloring (optional)"},{"name":"pink lemonade kool-aid","amount":0.5,"unit":"tsps","original":"1/2 – 3/4 tsp Pink Lemonade Kool-Aid"},{"name":"powdered sugar","amount":0.25,"unit":"cups","original":"1/4 C Powdered Sugar"},{"name":"sugar","amount":1.25,"unit":"cups","original":"1 1/4 C Sugar"}]'::jsonb, '["Prepare a cookie sheet by greasing with non-stick cooking spray. Preheat oven to 35","Cream butter and sugar together in your mixer, scraping the sides of your bowl.","Add your egg and mix well.","Mix in baking powder, baking soda, Kool-Aid and cornstarch. Once its well mixed (the Kool-Aid will be mixed once it turns your dough pink), add a drop of pink food coloring, if more color is desired. Next, start adding your flour a half cup at a time until its all added.","Roll the dough into walnut-sized balls and roll in the powder sugar, giving them a light coating.","Place 2 apart on a room-temp baking sheet (let your sheet cool in between batches if you are reusing the same one).","Bake in the oven 9-10 minutes, they wont brown too much, so watch them closely. Over-baking will make them hard and crunchy!I hope you enjoy these! I will be baking another batch soon, we have a neighborhood barbecue coming up and I know these will be perfect!Want more Whistle and Ivy? Subscribe here! And dont forget to follow on Instagram and Pinterest.You may also like these Avocado Mint Chocolate Sugar Cookies or this Honey Kool-Aid Taffy","Until next time,JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (716300, 'Plantain Pizza', 'Plantain Pizzan is a Mediterranean main course.  One serving contains 657 calories, 27g of protein, and 23g of fat.', 'https://img.spoonacular.com/recipes/716300-312x231.jpg', 'https://www.afrolems.com/2014/03/08/plantain-pizza/', 45, 3, array['Mediterranean', 'Italian', 'European']::text[], array['lunch', 'dinner']::text[], '[{"name":"beef","amount":1,"unit":"cup","original":"1 cup of chopped Beef"},{"name":"bell pepper","amount":1,"unit":"","original":"1 Bell pepper (Blended)"},{"name":"bell peppers","amount":1,"unit":"handful","original":"1 handful of chopped bell peppers"},{"name":"bread flour","amount":2,"unit":"cups","original":"2 cups of Bread flour"},{"name":"seasoning cube","amount":3,"unit":"servings","original":"Seasoning cube"},{"name":"oil","amount":1,"unit":"Tbsp","original":"1 tablespoon of oil"},{"name":"oil","amount":1,"unit":"tsp","original":"1 teaspoon oil"},{"name":"onions","amount":1,"unit":"handful","original":"A handful of chopped onions"},{"name":"over-ripe plantain","amount":1,"unit":"","original":"1 over-ripe plantain (Mashed)"},{"name":"salt","amount":1,"unit":"tsp","original":"1 teaspoon salt"},{"name":"sugar","amount":0.5,"unit":"tsps","original":"1/2 teaspoon of sugar"},{"name":"tomato)","amount":1,"unit":"","original":"1 tomato(Blended)"},{"name":"water","amount":0.75,"unit":"cups","original":"3/4 cup of water"},{"name":"yeast","amount":1.5,"unit":"tsps","original":"1.5 teaspoons of yeast"}]'::jsonb, '["Dissolve the yeast in warm water and leave to stand for about 5 minutes.","Mix the oil, flour, salt, sugar and mashed plantain and pour in the dissolved yeast.Knead the dough till its elastic which may take aBout 15-20 minutes By hand or 10 minutes in a mixer.Coat a Bowl lightly with oil and place the dough in it. Cover with a plastic wrap and leave to rise between 1.5 – 2 hours.While the dough is rising, heat up the oil for the sauce, fry the Blended tomato and pepper, season and stir fry the Beef in the tomato sauce. Set aside.When the dough rises, divide into two.","Sprinkle some flour on a flat surface and with a rolling pin, flatten out the dough but not excessively.","Cut the dough into your desired shape, rub some oil on it and spread your sauce and toppings on it and set aside.","Heat up your oven to 350 F and place your pizza dough on a lightly oiled foil pan and","Bake for 12-15 mins.","Serve warm"]'::jsonb),
  (657579, 'Quick Chicken Enchilada Soup', 'If you have approximately 45 minutes to spend in the kitchen, Quick Chicken Enchilada Soup might be a super gluten free recipe to try.  One serving contains 646 calories, 34g of protein, and 25g of fat.', 'https://img.spoonacular.com/recipes/657579-312x231.jpg', 'https://www.foodista.com/recipe/WSQ5JZ7W/quick-chicken-enchilada-soup', 45, 4, array['Mexican']::text[], array['lunch', 'dinner']::text[], '[{"name":"corn","amount":15,"unit":"oz","original":"1 (15 oz) can of corn, drained"},{"name":"black beans","amount":15,"unit":"oz","original":"1 (15 oz) can black beans, drained and rinsed"},{"name":"canned tomatoes","amount":14.5,"unit":"oz","original":"1 14.5-ounce can diced tomatoes (I used the kind with sweet onion in it)"},{"name":"swanson premium chicken","amount":12.5,"unit":"oz","original":"1 (12.5 oz) can Swanson Premium Chunk Chicken, drained and broken up"},{"name":"enchilada sauce","amount":10,"unit":"oz","original":"1 (10 oz) can enchilada sauce"},{"name":"campbell''s cream of mushroom soup","amount":10.75,"unit":"oz","original":"1 (10 3/4 oz) can Campbell''s cream of mushroom soup"},{"name":"milk","amount":1.5,"unit":"cups","original":"1 1/2 cups milk (I used skim)"},{"name":"tortilla chips","amount":4,"unit":"servings","original":"tortilla chips"},{"name":"cheese","amount":4,"unit":"servings","original":"shredded cheese"}]'::jsonb, '["In a large sauce pan, combine corn, beans, tomatoes, chicken, enchilada sauce, mushroom soup, and milk.","Cook over medium heat while stirring for 15 minutes.","Serve over tortillas chips and topped with shredded cheese."]'::jsonb),
  (657939, 'Ratatouille With Brie', 'You can never have too many main course recipes, so give Ratatouille With Brie a try.  One portion of this dish contains roughly 14g of protein, 45g of fat, and a total of 490 calories.', 'https://img.spoonacular.com/recipes/657939-312x231.jpg', 'https://www.foodista.com/recipe/YKQ5H3TL/ratatouille-with-brie', 45, 4, array['Mediterranean', 'French', 'European']::text[], array['snack', 'lunch', 'dinner']::text[], '[{"name":"brie log such as alouette","amount":1,"unit":"","original":"1 Brie Log such as Alouette"},{"name":"eggplant","amount":1,"unit":"small","original":"1 small eggplant"},{"name":"olive oil","amount":4,"unit":"oz","original":"4 oz. olive oil (for sautéing and garnishing)"},{"name":"zucchini","amount":1,"unit":"","original":"1 zucchini"},{"name":"squash","amount":1,"unit":"","original":"1 yellow squash"},{"name":"plum tomatoes","amount":2,"unit":"","original":"2 ripe plum tomatoes"},{"name":"thyme","amount":1,"unit":"tsp","original":"1 tsp. thyme (chopped)"}]'::jsonb, '["Remove outer peel from eggplant and dice into  inch pieces","Heat 1-2 oz. of olive oil in a heavy gauge skillet","Saut the diced eggplant for 2-3 minutes then place on a towel to drain","After draining place cooked eggplant into a small oval casserole dish","Preheat oven to 375 F","Carefully slice the zucchini , yellow squash , and tomatoes about  inch even slices","Slice the Brie also into  inch slices (utilizing a cheese wire makes simplifies this)","Begin placing sliced yellow squash , zucchini , sliced Brie and tomatoes in a shingled pattern working from the outside of the casserole towards the center","When all vegetables and cheese are placed in the casserole, drizzle with the remaining olive oil and sprinkle with chopped thyme","Season with salt and pepper and bake in the oven for 10-15 minutes until bubbly"]'::jsonb),
  (658967, 'Saffron Chicken Tikka', 'Saffron Chicken Tikka could be just the gluten free recipe you''ve been looking for.  This recipe serves 3.', 'https://img.spoonacular.com/recipes/658967-312x231.jpg', 'https://www.foodista.com/recipe/GV8J2V28/saffron-chicken-tikka', 45, 3, array['Indian', 'Asian']::text[], array['lunch', 'dinner']::text[], '[{"name":"chicken breasts","amount":12.346,"unit":"oz","original":"350 grams Chicken Breasts (cubed approx. in 1 inch pieces)"},{"name":"cinnamon stick","amount":0.5,"unit":"inch","original":"½ inch cinnamon stick"},{"name":"cardamom seeds","amount":1,"unit":"","original":"1 black cardamom seeds (I used only half the amount of its seeds)"},{"name":"cardamom seeds","amount":2,"unit":"","original":"2 green cardamom seeds"},{"name":"cloves","amount":5,"unit":"","original":"5 cloves"},{"name":"chillies","amount":2,"unit":"","original":"2-3 green chillies"},{"name":"garlic paste","amount":0.5,"unit":"tsps","original":"½ tsp garlic paste"},{"name":"ginger paste","amount":0.5,"unit":"tsps","original":"½ tsp ginger paste"},{"name":"pepper corns","amount":8,"unit":"","original":"8-10 white pepper corns"},{"name":"saffron","amount":1,"unit":"pinch","original":"A pinch of saffron"},{"name":"milk","amount":2,"unit":"tsps","original":"2 tsp milk"},{"name":"salt","amount":3,"unit":"servings","original":"Salt to taste"},{"name":"skewers","amount":9,"unit":"","original":"9-10 skewers"},{"name":"skewers","amount":9,"unit":"","original":"9-10 skewers"}]'::jsonb, '["Soak saffron in warm milk for 15 to 20 minutes.","In the meantime, dry roast the cinnamon stick, black cardamom seeds, green cardamom seeds, pepper corns and cloves. Pound them to a powder (not very fine).","In a mortar and pestle grind the green chillies to a paste. (Using a pinch of coarse salt will help)","Mix all the ingredients together and your marinade is ready.","Ensure that you pat dry the chicken cubes.","Transfer the chicken in a bowl","Add the marinade to the chicken cubes and mix it well so that all pieces are well coated.","Cover the bowl with a cling film and put it in the refrigerator.","Leave the chicken to marinate over-night. (I marinated for almost 18 hours and the result was moist and tender chicken tikkas)","I grilled these tikkas in my non-stick grill pan. Using a non-stick pan helped me keep the amount of oil to minimal.","Soak the skewers in water for at least half an hour before you intend to serve them.","Now take the skewers and start skewering the chicken pieces on them. I leave a little space in between the chicken pieces; else they stick together and do not get cooked well. (Perhaps the reason could be pan grilling)","Keep the skewers ready and then heat the pan (medium hot).","You can use an oil spray or pour a little oil using a spoon in a linear fashion across the grill pan.","Place the skewers over the oiled pan and grill them on medium low heat.","It will take approximately 45 seconds to a minute for one side to get cooked.","Then turn around and cook the other side the same way.","Serve them hot as a starter or as a main course with Bakarkhani!! Bon apptit!!"]'::jsonb),
  (776505, 'Sausage & Pepperoni Stromboli', 'Sausage & Pepperoni Stromboli takes about 28 minutes from beginning to end.  This recipe serves 6.', 'https://img.spoonacular.com/recipes/776505-312x231.jpg', 'http://asouthern-soul.blogspot.com/2014/11/sausage-pepperoni-stromboli.html', 28, 6, '{}'::text[], array['lunch', 'dinner']::text[], '[{"name":"egg","amount":1,"unit":"","original":"1 egg"},{"name":"sausage","amount":1,"unit":"lb","original":"1 lb Italian sausage"},{"name":"parmesan cheese","amount":1,"unit":"cup","original":"1 cup shredded Parmesan cheese"},{"name":"pepperoni","amount":1,"unit":"pkg","original":"1 package sliced pepperoni"},{"name":"roll of pizza dough","amount":1,"unit":"ball","original":"1 ball or roll of pizza dough (homemade is great but I used store-bought)"},{"name":"pizza sauce","amount":2,"unit":"cups","original":"2 cups pizza sauce"},{"name":"mozzarella cheese","amount":1,"unit":"cup","original":"1 cup shredded mozzarella cheese"}]'::jsonb, '["Cook Italian sausage in a medium skillet until browned.","Drain on paper towels and crumble into small pieces.","Heat oven to 450 degrees.","Place parchment paper on a baking pan and lightly flour.","Roll dough out to form a large rectangle.","Brush a thin layer of pizza sauce on dough.","Layer on crumbled sausage then mozzarella cheese.","Place pepperoni slices on top of cheese then sprinkle with 3/4 cup Parmesan cheese.Gently roll in short sides of dough to form a seal around filling.Starting on long side of dough, carefully roll into one third of Stromboli. Using parchment, roll dough again until reaching opposite end. Pinch together and place seam side down.","Mix egg with 1 tablespoon of water.","Brush egg mixture over Stromboli and sprinkle with remaining 1/4 Parmesan cheese.","Place in oven and IMMEDIATELY TURN OVEN DOWN to 350 degrees.","Bake for approximately 18 minutes.","Remove from oven and let rest for 10 minutes. Test center of turnover. If dough is not completely cooked, slice Stromboli in half and bake for additional 5-8 minutes.","Serve with warm pizza sauce"]'::jsonb),
  (997285, 'Shrimp and Asparagus Foil Packs with Garlic Lemon Butter Sauce', 'Shrimp and Asparagus Foil Packs with Garlic Lemon Butter Sauce is a main course that serves 4.  One serving contains 353 calories, 38g of protein, and 20g of fat.', 'https://img.spoonacular.com/recipes/997285-312x231.jpg', 'http://eat-sleep-recipes-repeat.blogspot.com/2017/07/shrimp-and-asparagus-foil-packs-with.html?m=1', 45, 4, '{}'::text[], array['lunch', 'dinner']::text[], '[{"name":"asparagus","amount":1,"unit":"lb","original":"1 lb medium thickness asparagus woody ends trimmed"},{"name":"butter","amount":6,"unit":"Tbsps","original":"6 Tbsp butter diced into small cubes"},{"name":"chicken broth","amount":3,"unit":"Tbsps","original":"3 Tbsp dry white wine or chicken broth"},{"name":"fresh parsley","amount":2,"unit":"Tbsps","original":"2 Tbsp chopped fresh parsley"},{"name":"garlic","amount":4,"unit":"tsps","original":"4 tsp minced garlic"},{"name":"lemon juice","amount":1.5,"unit":"Tbsps","original":"1 1/2 Tbsp fresh lemon juice"},{"name":"lemon zest","amount":2,"unit":"tsps","original":"2 tsp lemon zest"},{"name":"salt and pepper","amount":4,"unit":"servings","original":"Salt and freshly ground black pepper"},{"name":"shrimp","amount":1.5,"unit":"lb","original":"1 1/2 lbs large (21/25) shrimp peeled and deveined*"}]'::jsonb, '["Preheat a grill to medium-high heat (about 400 - 425 degrees).","Cut 4 sheets of 14 by 12-inch heavy duty aluminum foil then lay each piece separately on countertop.","Divide shrimp among packets near center then place asparagus to one side of the shrimp (going the long direction of the foil).","Pour 1/2 Tbsp white wine over each.","Sprinkle over garlic (1 tsp per packet) and lemon zest then season with salt and pepper. Divide butter pieces evenly among packets layering them over the shrimp and asparagus. Wrap packets in and crimp edges together then wrap ends up (don''t wrap too tight - keep a little extra space inside for heat to circulate).","Grill, sealed side upward, until shrimp has cooked through, about 9 - 10 minutes. Carefully unwrap then drizzle with lemon juice (or just serve with lemon wedges for spritzing) and sprinkle with parsley.","Recipe source: Cooking Classy"]'::jsonb),
  (715573, 'Simple Skillet Lasagna', 'You can never have too many Mediterranean recipes, so give Simple Skillet Lasagnan a try.  For $2.', 'https://img.spoonacular.com/recipes/715573-312x231.jpg', 'https://www.pinkwhen.com/skillet-lasagna/', 35, 5, array['Mediterranean', 'Italian', 'European']::text[], array['lunch', 'dinner']::text[], '[{"name":"basil and basil sprig","amount":1,"unit":"leaf","original":"basil leaves and basil sprig"},{"name":"tomatoes","amount":56,"unit":"oz","original":"2 28oz cans peeled tomatoes"},{"name":"garlic","amount":3,"unit":"cloves","original":"3 cloves thinly sliced and chopped garlic"},{"name":"sausage","amount":1.5,"unit":"lb","original":"1.5lbs Italian sausage"},{"name":"m zarella cheese","amount":1,"unit":"oz","original":"mozzarella cheese"},{"name":"onion","amount":1,"unit":"small","original":"1 small chopped onion"},{"name":"oregano flakes","amount":5,"unit":"servings","original":"oregano flakes"},{"name":"no boil lasagna noodles","amount":5,"unit":"servings","original":"no boil lasagna noodles"},{"name":"pepper flakes","amount":0.5,"unit":"tsps","original":"½ tsp red pepper flakes"},{"name":"ricotta cheese","amount":5,"unit":"servings","original":"ricotta cheese"},{"name":"salt and pepper","amount":5,"unit":"servings","original":"salt and pepper"}]'::jsonb, '["In a large saute pan, heat oil on high.","Add sausage and cook until browned, about 3-5 minutes.","Transfer to a side bowl and set aside.Reduce the heat to medium low and add your onion, garlic, and pepper flakes. Cook until onions are softened, about 8 minutes.","Add your oregano, tomatoes and their juices (crushing the whole tomatoes with your hands or a mixer if you prefer), the basil sprig, and the cooked sausage.","Add salt and pepper and simmer for about 5 minutes.Break half of the lasagna noodles in half and place into the meat mixture under the sausage. Distribute them evenly throughout. Take the other half of the noodles and use a spoon to submerge them down into the pan.Dollop Ricotta over lasagna and mix in with the sauce. Top with Mozzarella and bake in the oven on 325 degrees for 15 minutes. Top with basil, then remove from heat and allow to cool before serving."]'::jsonb),
  (716407, 'Simple Whole Wheat Crepes', 'Simple Whole Wheat Crepes might be just the breakfast you are searching for.  This recipe makes 4 servings with 272 calories, 10g of protein, and 14g of fat each.', 'https://img.spoonacular.com/recipes/716407-312x231.jpg', 'https://fullbellysisters.blogspot.com/2014/11/simple-whole-wheat-crepes.html', 45, 4, array['Mediterranean', 'French', 'European']::text[], array['breakfast', 'dessert']::text[], '[{"name":"butter","amount":3,"unit":"Tbsps","original":"3 Tablespoons butter, melted"},{"name":"eggs","amount":3,"unit":"","original":"3 eggs"},{"name":"maple syrup","amount":1,"unit":"Tbsp","original":"1 Tablespoon maple syrup (optional)"},{"name":"milk","amount":1,"unit":"cup","original":"1 cup milk"},{"name":"sea salt","amount":1,"unit":"pinch","original":"pinch of sea salt"},{"name":"flour","amount":1,"unit":"cup","original":"1 cup white whole wheat flour"}]'::jsonb, '["Place all ingredients in a blender and mix until smooth. The batter should be thin.","Let it sit at least 30 minutes—or even overnight.When it comes time to cook your crêpes you can do it the traditional way, in a crêpe pan, or you can use an electric crêpe maker."]'::jsonb),
  (715391, 'Slow Cooker Chicken Taco Soup', 'Forget going out to eat or ordering takeout every time you crave Mexican food.  Try making Slow Cooker Chicken Taco Soup at home.', 'https://img.spoonacular.com/recipes/715391-312x231.jpg', 'https://www.pinkwhen.com/slow-cooker-chicken-taco-soup-recipe/', 485, 6, array['Mexican']::text[], array['lunch', 'dinner']::text[], '[{"name":"black beans","amount":15,"unit":"oz","original":"1 (15 oz.) can black beans"},{"name":"tomatoes","amount":20,"unit":"oz","original":"2 (10 oz.) cans diced tomatoes with green chilis"},{"name":"canned tomatoes","amount":15,"unit":"oz","original":"1 (15 oz.) can diced tomatoes"},{"name":"chili beans","amount":15,"unit":"oz","original":"1 (15 oz.) can chili beans"},{"name":"kernal corn","amount":15,"unit":"oz","original":"1 (15 oz.) can whole kernal corn"},{"name":"onion","amount":1,"unit":"large","original":"1 large red onion (finely chopped)"},{"name":"chicken breasts","amount":3,"unit":"","original":"3 boneless skinless chicken breasts (cut into 1\" cubes)"}]'::jsonb, '["Once you have all of your ingredients added, allow it to cook all day for 8 hours on low. If you are wanting to make this a little faster, turn it on high and cook for 4 hours.When your Chicken Taco Soup is ready to serve, add in some crushed tortilla shells, shredded cheddar cheese, and a little sour cream."]'::jsonb),
  (715419, 'Slow Cooker Spicy Hot Wings', 'Slow Cooker Spicy Hot Wings might be a good recipe to expand your hor d''oeuvre recipe box.  This recipe serves 4 and costs $1.', 'https://img.spoonacular.com/recipes/715419-312x231.jpg', 'https://www.pinkwhen.com/slow-cooker-spicy-hot-wings/', 14, 4, array['American']::text[], array['lunch', 'dinner', 'snack']::text[], '[{"name":"brown sugar","amount":0.5,"unit":"cups","original":"½ cup brown sugar"},{"name":"cayenne pepper","amount":1,"unit":"tsp","original":"1 tsp cayenne pepper"},{"name":"regular chicken wings","amount":2,"unit":"lb","original":"2 - 4 pounds regular chicken wings"},{"name":"garlic","amount":1,"unit":"Tbsp","original":"1 Tbsp crushed garlic"},{"name":"louisiana hot sauce","amount":0.5,"unit":"cups","original":"½ cup Louisiana Hot sauce"}]'::jsonb, '["Yes, these are called SPICY hot wings for a reason. I like adding the brown sugar to give them a little sweeter taste, but it is by far a delicious spicy recipe more than anything.To get started, mix the brown sugar, crushed garlic, hot sauce, and cayenne pepper into a medium mixing bowl.","Mix well and then set aside.Take the cooking spray and spray the entire inside portion of the slow cooker AND also the wings. (Spraying the wings before you grill, bake, or cook chicken keeps the flavor and makes them super juicy. TRUST ME.)Take the wings and add them into the mixing bowl with your spices and toss to get a good even coat over the wings.","Place in the slow cooker on low for 4 hours. After 4hours, remove carefully and place on a prepared cookie sheet.","Place in the oven under broiler setting for 4-6 minutes, allowing the wings to get a little crisp.","Serve immediately with a little blue cheese dressing and celery."]'::jsonb),
  (798400, 'Spicy Black-Eyed Pea Curry with Swiss Chard and Roasted Eggplant', 'The recipe Spicy Black-Eyed Pea Curry with Swiss Chard and Roasted Eggplant could satisfy your Indian craving in around 45 minutes.  This recipe serves 6 and costs 94 cents per serving.', 'https://img.spoonacular.com/recipes/798400-312x231.jpg', 'https://www.foodandspice.com/2016/08/spicy-black-eyed-pea-curry-with-swiss.html', 45, 6, array['Indian', 'Asian']::text[], array['snack']::text[], '[{"name":"black-eyed peas","amount":2,"unit":"cups","original":"2/3 cup dried black-eyed peas (2 cups cooked)"},{"name":"curry powder","amount":2,"unit":"tsps","original":"2 teaspoons curry powder"},{"name":"garam masala","amount":0.5,"unit":"tsps","original":"1/2 teaspoon garam masala"},{"name":"globe","amount":1,"unit":"large","original":"1 large globe or Italian eggplant"},{"name":"ground coriander","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground coriander"},{"name":"ground cumin","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground cumin"},{"name":"ground mustard powder","amount":0.5,"unit":"tsps","original":"1/2 teaspoon ground mustard powder"},{"name":"juice of lemon","amount":3,"unit":"","original":"juice from 1 lemon (3 tablespoons)"},{"name":"olive oil","amount":2,"unit":"tsps","original":"2 teaspoons olive oil"},{"name":"chilies","amount":2,"unit":"","original":"2 green or red chilies, seeded and finely chopped"},{"name":"sea salt","amount":1,"unit":"tsp","original":"1 teaspoon sea salt, or to taste"},{"name":"shallots","amount":2,"unit":"","original":"2 shallots, mined"},{"name":"swiss chard","amount":1,"unit":"bunch","original":"1 bunch Swiss chard, trimmed and chopped"},{"name":"tomato","amount":1,"unit":"medium","original":"1 medium tomato, finely chopped"},{"name":"water","amount":5,"unit":"Tbsps","original":"5 tablespoons water, or more as needed"}]'::jsonb, '["Rinse the black-eyed peas and soak in several inches of water for 6 hours or overnight.","Drain and rinse, then transfer to a large saucepan and cover with fresh water. Bring to a boil, reduce heat to medium-low, cover, and simmer for 40 to 60 minutes. Take care not to overcook  the beans should be tender but not be falling apart.","Drain and set aside.To prepare the eggplant, cut of the stem and bottom edge and then cut in half lengthwise. Score the flesh into diagonal 1-inch lines, then turn and score again until you have a diagonal pattern. Take care not to cut through the skin.","Sprinkle with some salt and let sit for 40 minutes. Rinse and squeeze out any excess water.","Brush the eggplant with some oil and transfer to a roasting pan.","Bake in a preheated 400 oven until the flesh appears collapsed and is wrinkly.","Remove from heat and let cool for about 10 minutes, season with a bit of salt, and remove the flesh from the eggplant. If there is too much water, drain in a strainer. Set aside.","Heat the oil over medium heat in the same saucepan used to cook the black-eyed peas. When hot, toss in the shallots and chilies and saut for 2 to 3 minutes. Now add the spices and stir for another minute, until fragrant.","Add the tomato, cook for another few minutes, and then add the eggplant and black-eyed peas, and cook for another few minutes, stirring often.","Pour a few tablespoons of water into the pan and add handfuls of chard at a time until wilted.","Add more water as necessary.","Add the lemon juice and salt to taste near the end of the cooking time.","Remove from heat, cover, and let sit for a few minutes before serving."]'::jsonb),
  (715569, 'Strawberry Cheesecake Chocolate Crepes', 'Need a lacto ovo vegetarian breakfast?  Strawberry Cheesecake Chocolate Crepes could be an excellent recipe to try.', 'https://img.spoonacular.com/recipes/715569-312x231.jpg', 'https://www.pinkwhen.com/strawberry-cheesecake-chocolate-crepes/', 40, 4, array['Mediterranean', 'French', 'European']::text[], array['breakfast', 'dessert']::text[], '[{"name":"cream cheese","amount":8,"unit":"oz","original":"8 oz cream cheese"},{"name":"strawberries","amount":1.25,"unit":"cups","original":"1 1/4 cup diced strawberries"},{"name":"vanilla extract","amount":1,"unit":"tsp","original":"1 tsp vanilla extract"},{"name":"lemon juice","amount":1,"unit":"tsp","original":"1 tsp lemon juice"},{"name":"granulated sugar","amount":2,"unit":"Tbsps","original":"2 tbsp granulated sugar"},{"name":"flour","amount":1.5,"unit":"cups","original":"1 1/2 cups all-purpose flour"},{"name":"cocoa powder","amount":0.25,"unit":"cups","original":"1/4 cup cocoa powder unsweetened"},{"name":"kosher salt","amount":0.125,"unit":"tsps","original":"1/8 tsp kosher salt"},{"name":"eggs","amount":3,"unit":"","original":"3 eggs"},{"name":"milk","amount":1.25,"unit":"cups","original":"1 1/4 cups milk"},{"name":"water","amount":0.25,"unit":"cups","original":"1/4 cup water"},{"name":"butter","amount":4,"unit":"Tbsps","original":"4 tbsp unsalted butter melted"},{"name":"vanilla extract","amount":0.5,"unit":"tsps","original":"1/2 tsp vanilla extract"}]'::jsonb, '["How to Make Strawberry Creme Cheese Filling","Add cream cheese, strawberries, vanilla extract, lemon juice, and granulated sugar into a medium-sized mixing bowl.","Use a hand mixer, wooden spoon, or spatula to mix ingredients.","Mix until smooth.","Set aside.","How to Blend Chocolate Crepes Ingredients","Combine flour, sugar, cocoa powder, salt, and eggs to a food processor or blender.","If using a food processor, keep it running as you add milk and water. Continue to pulse intil blended well.","Pour in melted butter and vanilla extract.","Set bowl aside.","How to Make Chocolate Crepes","Heat crepe pan or 8\"-10\" omelet pan over medium heat.","Pour 1/4 cup of batter directly into the middle of the pan and swirl to cover the bottom.","Cook the crepe for 2-3 minutes or until the bottom is light brown and the edges are completely set.","Flip the crepe over and cook for an additional minute.","Transfer to a serving platter and repeat for the rest of the batter."]'::jsonb),
  (663100, 'Thai Cucumber Salad (By Roz)', 'You can never have too many side dish recipes, so give Thai Cucumber Salad (By Roz) a try.  This recipe serves 6 and costs $1.', 'https://img.spoonacular.com/recipes/663100-312x231.jpg', 'https://www.foodista.com/recipe/KNFYV5H8/thai-cucumber-salad-by-roz', 45, 6, array['Thai', 'Asian']::text[], array['snack']::text[], '[{"name":"cilantro","amount":1,"unit":"Tbsp","original":"1 tablespoon chopped cilantro"},{"name":"cucumbers","amount":2,"unit":"","original":"2 cucumbers, seeded, cubed or sliced (you can also peel them if you like)"},{"name":"jalapeno pepper","amount":0.5,"unit":"","original":"1/2 jalapeno pepper, seeded, and finely chopped"},{"name":"lime juice","amount":2,"unit":"Tbsps","original":"2 tablespoons freshly squeezed lime juice"},{"name":"lime zest","amount":1,"unit":"","original":"1 Zest of lime"},{"name":"onions","amount":0.25,"unit":"cups","original":"1/4 cup red or white onions, chopped"},{"name":"pepper flakes","amount":6,"unit":"servings","original":"Red pepper flakes"},{"name":"rice wine vinegar","amount":0.5,"unit":"cups","original":"1/2 cup rice wine vinegar"},{"name":"chop roasted peanuts","amount":0.5,"unit":"cups","original":"1/2 cup finely chop unsalted dry roasted peanuts (optional)"},{"name":"salt","amount":1,"unit":"tsp","original":"1 teaspoon salt"},{"name":"coconut & sesame oil","amount":2,"unit":"Tbsps","original":"2 tablespoons coconut & Sesame Oil or 3 Tbsp Peanut"},{"name":"soy sauce","amount":1,"unit":"Tbsp","original":"1 tablespoon soy sauce"},{"name":"sugar","amount":0.25,"unit":"cups","original":"1/4 cup sugar"},{"name":"thai garlic chili pepper sauce","amount":1,"unit":"Tbsp","original":"1 tablespoon Thai garlic chili pepper sauce"},{"name":"pepper","amount":0.25,"unit":"tsps","original":"1/4 teaspoon white pepper"}]'::jsonb, '["Blend all the dressing ingredients together.","Mix in all of the chopped vegetables, herb, and peanuts (if you want the peanuts).","Add more of any of the flavors that you prefer, which is the true Thai way.","Garnish each plate with cilantro leaves and sliced limes.","Serve with a patter of add-ins:Lime slices, red pepper flakes, chopped cilantro, chopped peanuts, Thai sweet chili sauce, sugar, salt, etc. for your guests to add more of their favorite flavors."]'::jsonb),
  (663113, 'Thai Green Mango Salad', 'Thai Green Mango Salad could be just the gluten free, dairy free, paleolithic, and primal recipe you''ve been looking for.  This recipe makes 6 servings with 133 calories, 4g of protein, and 4g of fat each.', 'https://img.spoonacular.com/recipes/663113-312x231.jpg', 'https://www.foodista.com/recipe/JRRRFDVQ/thai-green-mango-salad', 45, 6, array['Thai', 'Asian']::text[], array['snack']::text[], '[{"name":"fish sauce","amount":6,"unit":"servings","original":"Fish sauce, to taste"},{"name":"thai palm sugar","amount":6,"unit":"servings","original":"Thai palm sugar, to taste"},{"name":"limes","amount":4,"unit":"","original":"4 limes"},{"name":"to 3 chilli padis","amount":2,"unit":"","original":"2 to 3 chilli padis"},{"name":"garlic","amount":1,"unit":"clove","original":"1 clove of garlic, mashed"},{"name":"shallots","amount":2,"unit":"","original":"2 shallots, mashed"},{"name":"shrimps","amount":1,"unit":"Tbsp","original":"1 tablespoon of dried shrimps, washed"},{"name":"tomato","amount":1,"unit":"","original":"1 tomato, cut into wedges"},{"name":"carrot","amount":1,"unit":"cup","original":"1 cup carrot, shredded"},{"name":"mangoes","amount":3,"unit":"cups","original":"3 cups raw green mangoes, shredded"},{"name":"long beans","amount":2,"unit":"inches","original":"2 inches long beans cut into 1 pieces"},{"name":"roasted coarse peanuts","amount":4,"unit":"Tbsps","original":"4 tablespoons roasted coarse peanuts"}]'::jsonb, '["Pound all the ingredients in a clay mortar using a wooden pestle, then add carrot and mangoes.","Serve chilled with roasted coarse peanuts."]'::jsonb),
  (663177, 'Thai-Style Mussels', 'If you want to add more gluten free, dairy free, paleolithic, and primal recipes to your recipe box, Thai-Style Mussels might be a recipe you should try.  This recipe serves 3.', 'https://img.spoonacular.com/recipes/663177-312x231.jpg', 'https://www.foodista.com/recipe/VMQG43VB/thai-style-mussels', 45, 3, array['Thai', 'Asian']::text[], array['lunch', 'dinner', 'snack']::text[], '[{"name":"wine","amount":2,"unit":"Tbsps","original":"2 tablespoons dry white wine"},{"name":"garlic","amount":4,"unit":"Cloves","original":"4 Cloves garlic, pressed or crushed"},{"name":"stem lemongrass","amount":1,"unit":"","original":"1 stem lemongrass (white parts only)"},{"name":"mussels","amount":2.25,"unit":"lb","original":"1 kg ( - 2 1/4 lbs) mussels"},{"name":"olive oil","amount":1,"unit":"Tbsp","original":"1 tablespoon olive oil"},{"name":"chilies","amount":2,"unit":"tsps","original":"2-3 teaspoons red chilies, chopped"},{"name":"thai basil leaves","amount":1,"unit":"handful","original":"A handful of Thai basil leaves, roughly chopped"},{"name":"water","amount":3,"unit":"Tbsps","original":"3 tablespoons Water"}]'::jsonb, '["Scrub the outside of the mussels with a brush.","Remove and discard the beards.","Heat the oil in a wok or large pan add garlic, lemongrass and chili. Cook until slightly brown and fragrant.","Add the mussels to the wok and toss well.","Add in chinese rice wine, water, and Thai basil after about 3 minutes.","Mix well.","Put the lid back on for another 1 minutes or so until all the mussels are open (discard any that stay closed)."]'::jsonb),
  (715467, 'Turkey Pot Pie', 'You can never have too many main course recipes, so give Turkey Pot Pie a try.  This recipe serves 8 and costs $2.', 'https://img.spoonacular.com/recipes/715467-312x231.jpg', 'https://www.pinkwhen.com/turkey-pot-pie-recipe/', 45, 8, '{}'::text[], array['lunch', 'dinner']::text[], '[{"name":"pepper","amount":1,"unit":"tsp","original":"1 tsp black pepper"},{"name":"butter","amount":0.6666667,"unit":"cups","original":"2/3 cup butter"},{"name":"celery","amount":1,"unit":"cup","original":"1 cup chopped celery"},{"name":"celery seed","amount":0.5,"unit":"tsps","original":"1/2 tsp celery seed"},{"name":"chicken broth","amount":1.75,"unit":"cups","original":"1 3/4 cups chicken broth"},{"name":"flour","amount":0.6666667,"unit":"cups","original":"2/3 cups all-purpose flour"},{"name":"garlic powder","amount":0.5,"unit":"tsps","original":"1/2 tsp garlic powder"},{"name":"green beans","amount":20,"unit":"oz","original":"2 (10oz) cans green beans"},{"name":"seasoning","amount":0.5,"unit":"tsps","original":"1/2 tsp Italian seasoning"},{"name":"milk","amount":1.3333334,"unit":"cups","original":"1 1/3 cups milk"},{"name":"onion","amount":0.5,"unit":"cups","original":"1/2 cup chopped onion"},{"name":"onion powder","amount":0.5,"unit":"tsps","original":"1/2 tsp onion powder"},{"name":"peas and carrots","amount":20,"unit":"oz","original":"2 (10oz) cans of mixed peas and carrots"},{"name":"\" pie crusts","amount":4,"unit":"","original":"4 9″ pie crusts (not frozen)"},{"name":"salt","amount":1,"unit":"tsp","original":"1 tsp salt"},{"name":"turkey","amount":4,"unit":"cups","original":"4 cups cooked Turkey"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"1/2 tsp white pepper"}]'::jsonb, '["Preheat oven to 425 degrees. Melt the butter and add the celeryand onion to a medium pot and saute over medium heat for about 8 minutes.Step 2: Stir in 2/3 cup flour, salt and pepper, celery seed, onion powder, garlic powder, and Italian seasoning. Slowly whisk in the chicken broth and milk, stirring constantly until the the mixture begins to thicken and then simmer lightly until thickened.","Remove from heat and mix with the drained vegetables and turkey.Step 3: Fill two pie crusts with your turkey and vegetable mixture. Carefully top each pie with another pie crust, pinching the sides together.","Bake uncovered in the preheated oven until the pies are golden brown, about 30 minutes. If the tops of the pies are browning too quickly, place a sheet of foil over the pie crusts and continue to bake. Cool for about 10 minutes before serving.This has to be one of the most delicious pot pie recipes I have ever tasted! What a great way to use up that leftover turkey. Another great substitution for turkey would also be to use a Rotisserie chicken. MMmmmm. I will be trying that soon.Have you ever tried a pot pie recipe? What about a Turkey Pot Pie Recipe? Make sure to save this one for those cold and snowy days ahead!JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (664650, 'Vegetarian Chinese Pot Stickers', 'If you have roughly 45 minutes to spend in the kitchen, Vegetarian Chinese Pot Stickers might be a super dairy free recipe to try.  This recipe serves 24 and costs 25 cents per serving.', 'https://img.spoonacular.com/recipes/664650-312x231.jpg', 'https://www.foodista.com/recipe/KF58KP4Y/vegan-vegetarian-pot-stickers', 45, 24, array['Chinese', 'Asian']::text[], array['snack']::text[], '[{"name":"won ton wrappers","amount":24,"unit":"","original":"24 won ton wrappers"},{"name":"mushrooms","amount":8,"unit":"oz","original":"8 oz. mushrooms (your choice – I used half whites & half baby portobellos)"},{"name":"soy sauce","amount":1,"unit":"Tbsp","original":"1 Tbs. tamari or soy sauce"},{"name":"sriracha hot sauce","amount":1,"unit":"tsp","original":"1 tsp. sriracha hot sauce"},{"name":"ginger","amount":1,"unit":"tsp","original":"1 tsp. grated fresh ginger"},{"name":"garlic","amount":1,"unit":"tsp","original":"1 tsp. fresh garlic (pressed through a garlic press)"},{"name":"scallions","amount":2,"unit":"","original":"2 scallions, white & green parts, roughly chopped"},{"name":"little cornstarch","amount":24,"unit":"servings","original":"A little cornstarch"},{"name":"little vegetable oil","amount":24,"unit":"servings","original":"A little vegetable oil"},{"name":"water","amount":1,"unit":"cup","original":"1 cup water, divided"}]'::jsonb, '["Add all of the ingredients (except the wrappers, cornstarch, oil, and water) to the bowl of a food processor. Pulse until the mushrooms are finely minced and all of the ingredients are well combined. It will help if youve given the mushrooms a bit of a rough chop first, or if you use pre-sliced mushrooms.","Place a won ton wrapper on your work surface, turned so that it appears to be a diamond shape.","Place a teaspoon of filling in the middle of the wrapper.","Dip a fingertip into the bowl of water and trace along the two edges farthest from you. Bring up the end closest to you, fold over the filling, and pinch the edges together to seal. Make sure youve gently pressed the wrapper around the filling so there are no air pockets.","Stand up your little triangle pocket so that the filling side sits on your work surface. Fold the top point down, away from you, and pinch. Now, give the edges on either side of that fold 2 little pleats and pinch. Your pot sticker will now look like it has wings.","Place it on a large plate thats been dusted with a bit of cornstarch, to prevent sticking.  (Traditionally, pot stickers are made with round dumpling wrappers, so if you have them, you can skip the part about folding the top point down.)","Heat the skillet over medium-high heat.","Brush just a few drops of oil onto the hot pan surface, and place 12 of the pot stickers, upright, into the pan. Allow the bottoms to brown. Carefully add 1/2 cup water to the pan and cover it quickly. Cook for about 3-4 minutes, or until all of the water has been absorbed.","Remove the pot stickers immediately to another plate to keep warm, and repeat the procedure with the rest of the uncooked ones.","*Feel like you have to have meat? Substitute 4 oz. of ground chicken (or pork, if you must) for half of the mushrooms, just dont run it through the food processor.","Mix the processed ingredients with the ground chicken thoroughly and fill the wrappers as before.","Add a full cup of water (instead of 1/2 cup) to the pan, and steam until the water evaporates, about 5-6 minutes."]'::jsonb),
  (945221, 'Watching What I Eat: Peanut Butter Banana Oat Breakfast Cookies with Carob / Chocolate Chips', 'If you want to add more gluten free and dairy free recipes to your repertoire, Watching What I Eat: Peanut Butter Bananan Oat Breakfast Cookies with Carob / Chocolate Chips might be a recipe you should try.  This recipe makes 16 servings with 103 calories, 4g of protein, and 5g of fat each.', 'https://img.spoonacular.com/recipes/945221-312x231.jpg', 'http://watching-what-i-eat.blogspot.com/2012/06/peanut-butter-banana-oat-breakfast.html', 45, 16, '{}'::text[], array['breakfast']::text[], '[{"name":"bananas","amount":2,"unit":"","original":"2 ripe bananas, mashed until smooth & creamy"},{"name":"butter flavor shortening","amount":1,"unit":"tsp","original":"1 tsp butter flavor extract ** (optional)"},{"name":"chocolate chips","amount":0.25,"unit":"cups","original":"1/4 cup carob or chocolate chips (**optional)"},{"name":"creamy peanut butter","amount":0.33333334,"unit":"cups","original":"1/3 cup peanut butter - creamy or chunky"},{"name":"nuts","amount":0.25,"unit":"cups","original":"1/4 cup chopped nuts (peanut, walnut, or your favorite)"},{"name":"oatmeal","amount":1.5,"unit":"cups","original":"1 1/2 cups quick oatmeal - uncooked (or use old fashioned oats for more oatmeal texture)"},{"name":"unsweetened applesauce","amount":0.6666667,"unit":"cups","original":"2/3 cup unsweetened applesauce"},{"name":"vanilla extract","amount":1,"unit":"tsp","original":"1 tsp vanilla extract"},{"name":"vanilla protein powder","amount":1,"unit":"scoop","original":"1 scoop vanilla protein powder ** (can be made without, cookie will just be lower in protein)"}]'::jsonb, '["Preheat heat oven to 350 degrees.In a large bowl, mix mashed banana & peanut butter until completely combined then add in the applesauce, vanilla protein powder & the extract(s) ~ mix again until all are completely combined.","Add in the oatmeal & nuts to the banana mixture & combine. (** add the optional carob / chocolate chips at this time if you want them mixed throughout)","Let dough rest for 10 minutes.Drop cookie dough, by spoonfuls, onto a parchment paper lined cookie sheet & flatten cookies into circles. (** if you just want the carob / chocolate chips on the top of the cookies, add now)","Bake cookies approx. 20-30 minutes (some like their cookies less cooked, some cooked more - try it both ways to find which works best for your tastes) or until golden brown & done.","Remove from oven & let rest on cookie sheet for 5 minutes, then move to cooling rack. (if you want the traditional fork tong marks on the cookies, use a pizza cutter or sharp knife to score the tops of the cookies while they''re still warm)When cookies are completely cool, store in a covered container. Enjoy!...or with a cuppa tea."]'::jsonb),
  (665484, 'Xocai Oatmeal Dark Chocolate No-Bake Cookies', 'Xocai Oatmeal Dark Chocolate No-Bake Cookies takes around 45 minutes from beginning to end.  This gluten free recipe serves 24 and costs 64 cents per serving.', 'https://img.spoonacular.com/recipes/665484-312x231.jpg', 'https://www.foodista.com/recipe/Q36G6FYW/xocai-oatmeal-dark-chocolate-no-bake-cookies', 45, 24, array['Thai', 'Asian']::text[], array['dessert']::text[], '[{"name":"butter substitute","amount":0.5,"unit":"cups","original":"1/2 cup butter substitute"},{"name":"xocai healthy chocolate nugget","amount":1,"unit":"","original":"1 Xocai Healthy Chocolate Nugget, chopped"},{"name":"oats","amount":3,"unit":"cups","original":"3 cups oats"},{"name":"peanut butter","amount":2,"unit":"cups","original":"2 cup peanut butter"},{"name":"soy milk","amount":0.5,"unit":"cups","original":"1/2 cup soy milk"},{"name":"sugar substitute","amount":2,"unit":"cups","original":"2 cups sugar substitute"},{"name":"vanilla","amount":1,"unit":"tsp","original":"1 tsp vanilla"}]'::jsonb, '["Combine the first four ingredient in a medium sauce pan.","Heat mixture until it boils. Boils for 5 minutes, stirring constantly.","Remove from heat and stir in remaining ingredients.","Add the Nuggets last. Drop by spoonful onto wax paper or foil. Cookies will harden as they cool. Makes 24 cookies"]'::jsonb);
